import React from 'react';
import { createBrowserRouter, Outlet } from 'react-router';

import { NavigationSearchProvider } from './context/NavigationSearch';
import { Footer } from './components/Footer';
import { Header } from './components/Header';
import { PWAUpdateNotifier } from './components/PWAUpdateNotifier';
import { PAGE_SCROLL_ID } from './utils/pageScroll';
import { BandDetail } from './pages/BandDetail';
import { Favorites } from './pages/Favorites';
import { Home } from './pages/Home';
import { Impressum } from './pages/Impressum';
import { NotFound } from './pages/NotFound';
import { Schedule } from './pages/Schedule';
import { SharedSchedule } from './pages/SharedSchedule';

const basename =
  import.meta.env.BASE_URL.replace(/\/$/, '') || '/';

function RootLayout() {
  return (
    <NavigationSearchProvider>
    <div className="app-shell relative z-[1] flex h-dvh flex-col overflow-hidden">
      <Header />
      <div
        id={PAGE_SCROLL_ID}
        className="page-scroll min-h-0 flex-1 overflow-y-auto overscroll-y-contain"
        style={{ viewTransitionName: 'page-content' }}
      >
        <main className="container mx-auto px-4 py-8">
          <Outlet />
        </main>
      </div>
      <Footer />
      <PWAUpdateNotifier />
    </div>
    </NavigationSearchProvider>
  );
}

export const router = createBrowserRouter(
  [
    {
      path: '/',
      element: <RootLayout />,
      children: [
        { index: true, element: <Home /> },
        { path: 'schedule', element: <Schedule /> },
        { path: 'favorites', element: <Favorites /> },
        { path: 'band/:id', element: <BandDetail /> },
        { path: 'shared', element: <SharedSchedule /> },
        { path: 'impressum', element: <Impressum /> },
        { path: '*', element: <NotFound /> },
      ],
    },
  ],
  { basename },
);
