import { EventWithDetails, Schedule } from '../models/types';
import {
  getAllEventsWithDetails,
  getFavoriteEventsWithDetails,
  loadSchedule,
  pruneFavoritesToSchedule,
  saveSchedule,
  sortEventsByDateTime,
} from './dataUtils';
import { getHomePicksSection, isEventUpcoming, type HomePicksSection } from './scheduleTimelineUtils';
import { enrichScheduleLocations, VenueCatalog } from './venueData';

export type ScheduleSnapshot = {
  schedule: Schedule;
  events: EventWithDetails[];
  uniqueDates: string[];
};

export type HomeSnapshot = {
  schedule: Schedule;
  upcomingPool: EventWithDetails[];
  homePicks: HomePicksSection | null;
};

export type FavoritesSnapshot = {
  schedule: Schedule;
  favoriteEvents: EventWithDetails[];
  uniqueDates: string[];
};

export function buildScheduleSnapshot(schedule: Schedule): ScheduleSnapshot {
  const events = sortEventsByDateTime(getAllEventsWithDetails(schedule));
  const uniqueDates = Array.from(new Set(events.map((event) => event.date)));
  return { schedule, events, uniqueDates };
}

/**
 * Loads curated venue metadata (coordinates, addresses) from JSON.
 */
async function loadVenueCatalog(): Promise<VenueCatalog> {
  try {
    const response = await fetch('/data/venues.json');
    if (!response.ok) {
      return {};
    }
    return await response.json();
  } catch (error) {
    console.warn('Could not load venue catalog:', error);
    return {};
  }
}

/**
 * Loads the schedule data from the JSON file
 * @returns Promise that resolves to the schedule data
 */
export async function loadScheduleData(): Promise<Schedule> {
  try {
    const [scheduleResponse, venueCatalog] = await Promise.all([
      fetch('/data/schedule.json'),
      loadVenueCatalog(),
    ]);

    if (!scheduleResponse.ok) {
      throw new Error(`Failed to load schedule data: ${scheduleResponse.status} ${scheduleResponse.statusText}`);
    }

    const schedule: Schedule = await scheduleResponse.json();
    const enrichedSchedule = enrichScheduleLocations(schedule, venueCatalog);

    // Save the schedule to localStorage for offline access
    saveSchedule(enrichedSchedule);
    pruneFavoritesToSchedule(enrichedSchedule);

    return enrichedSchedule;
  } catch (error) {
    console.error('Error loading schedule data:', error);

    // Try to load from localStorage as fallback
    const localSchedule = localStorage.getItem('wgt-schedule');
    if (localSchedule) {
      try {
        const catalog = await loadVenueCatalog();
        const schedule = enrichScheduleLocations(JSON.parse(localSchedule), catalog);
        pruneFavoritesToSchedule(schedule);
        return schedule;
      } catch (e) {
        console.error('Error parsing local schedule data:', e);
      }
    }

    // If all else fails, return an empty schedule
    return {
      bands: [],
      locations: [],
      events: [],
    };
  }
}

/**
 * Checks if the schedule data is already loaded in localStorage
 * @returns True if schedule data is available in localStorage
 */
export function isScheduleLoaded(): boolean {
  const scheduleData = localStorage.getItem('wgt-schedule');
  if (!scheduleData) return false;

  try {
    const schedule = JSON.parse(scheduleData);
    return (
      Array.isArray(schedule.bands) &&
      Array.isArray(schedule.locations) &&
      Array.isArray(schedule.events) &&
      schedule.events.length > 0
    );
  } catch (error) {
    return false;
  }
}

/** Synchronous snapshot for pages that can render cached schedule immediately. */
export function getCachedScheduleSnapshot(): ScheduleSnapshot | null {
  if (!isScheduleLoaded()) return null;

  const schedule = loadSchedule();
  if (!schedule) return null;

  return buildScheduleSnapshot(schedule);
}

export function buildHomeSnapshot(schedule: Schedule): HomeSnapshot {
  const sortedEvents = sortEventsByDateTime(getAllEventsWithDetails(schedule));
  const now = new Date();
  const upcomingPool = sortedEvents.filter((event) => isEventUpcoming(event, now));
  const favorites = sortEventsByDateTime(getFavoriteEventsWithDetails(schedule));
  return {
    schedule,
    upcomingPool,
    homePicks: getHomePicksSection(favorites),
  };
}

/** Synchronous snapshot so Home can paint picks/upcoming on first frame. */
export function getCachedHomeSnapshot(): HomeSnapshot | null {
  const schedule = loadSchedule();
  if (!schedule || !isScheduleLoaded()) return null;
  return buildHomeSnapshot(schedule);
}

export function buildFavoritesSnapshot(schedule: Schedule): FavoritesSnapshot {
  pruneFavoritesToSchedule(schedule);
  const favoriteEvents = sortEventsByDateTime(getFavoriteEventsWithDetails(schedule));
  const uniqueDates = Array.from(new Set(favoriteEvents.map((event) => event.date)));
  return { schedule, favoriteEvents, uniqueDates };
}

/** Synchronous snapshot so My schedule can paint day groups on first frame. */
export function getCachedFavoritesSnapshot(): FavoritesSnapshot | null {
  const schedule = loadSchedule();
  if (!schedule || !isScheduleLoaded()) return null;
  return buildFavoritesSnapshot(schedule);
}
