import { EventWithDetails, Location } from '../models/types';

export type TravelMode = 'walking' | 'driving' | 'transit';

export function formatLocationQuery(location: Location): string {
  if (location.lat != null && location.lng != null) {
    return `${location.lat},${location.lng}`;
  }

  return [location.name, location.address, location.city].filter(Boolean).join(', ');
}

export function buildGoogleMapsSearchUrl(location: Location): string {
  const query = formatLocationQuery(location);
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(query)}`;
}

export function buildAppleMapsSearchUrl(location: Location): string {
  const query = formatLocationQuery(location);
  return `https://maps.apple.com/?q=${encodeURIComponent(query)}`;
}

export function buildGoogleMapsDirectionsUrl(
  from: Location,
  to: Location,
  travelMode: TravelMode = 'walking',
): string {
  const origin = formatLocationQuery(from);
  const destination = formatLocationQuery(to);
  return `https://www.google.com/maps/dir/?api=1&origin=${encodeURIComponent(origin)}&destination=${encodeURIComponent(destination)}&travelmode=${travelMode}`;
}

export function buildAppleMapsDirectionsUrl(from: Location, to: Location): string {
  const origin = formatLocationQuery(from);
  const destination = formatLocationQuery(to);
  return `https://maps.apple.com/?saddr=${encodeURIComponent(origin)}&daddr=${encodeURIComponent(destination)}&dirflg=w`;
}

export type DayScheduleItem =
  | { type: 'event'; event: EventWithDetails }
  | { type: 'travel'; from: Location; to: Location; nextStartTime: string };

/** Insert travel hints between consecutive events at different venues (same-day lists). */
export function interleaveTravelHints(events: EventWithDetails[]): DayScheduleItem[] {
  const items: DayScheduleItem[] = [];

  for (let index = 0; index < events.length; index++) {
    const event = events[index];
    items.push({ type: 'event', event });

    const next = events[index + 1];
    if (next && event.locationId !== next.locationId) {
      items.push({
        type: 'travel',
        from: event.location,
        to: next.location,
        nextStartTime: next.startTime,
      });
    }
  }

  return items;
}
