import React from 'react';

import { EventWithDetails } from '../models/types';
import { formatDayConflictWarning, getDaySummary } from '../utils/scheduleTimelineUtils';
import { useFavorites } from '../utils/useFavorites';
import { DayHeader } from './DayHeader';
import { FavoritesTimeline } from './FavoritesTimeline';

interface FavoritesDaySectionProps {
  date: string;
  events: EventWithDetails[];
  isExpanded: boolean;
  onToggleExpanded: (date: string) => void;
  sourceInfo?: { name: string };
  showDaySummary?: boolean;
  showConflicts?: boolean;
  showTravelHints?: boolean;
}

export function FavoritesDaySection({
  date,
  events,
  isExpanded,
  onToggleExpanded,
  sourceInfo,
  showDaySummary = false,
  showConflicts = false,
  showTravelHints = false,
}: FavoritesDaySectionProps) {
  const { isFootprint } = useFavorites();
  const plannedEvents = events.filter((event) => isFootprint(event.id));
  const plannedCount = plannedEvents.length;

  const summaryParts = showDaySummary
    ? [
        getDaySummary(events),
        plannedCount > 0 ? `${plannedCount} planned` : null,
      ].filter((part): part is string => Boolean(part))
    : [];
  const summary = summaryParts.length > 0 ? summaryParts.join(' · ') : undefined;
  const conflictWarning = showDaySummary ? formatDayConflictWarning(plannedEvents) : undefined;

  return (
    <div className="mb-4 md:mb-8">
      <DayHeader
        date={date}
        eventCount={events.length}
        isExpanded={isExpanded}
        onToggle={onToggleExpanded}
        subtitle={summary}
        warning={conflictWarning}
      />
      {isExpanded && (
        <div className="mt-3 pl-0 md:pl-2">
          <FavoritesTimeline
            events={events}
            sourceInfo={sourceInfo}
            showConflicts={showConflicts}
            showTravelHints={showTravelHints}
          />
        </div>
      )}
    </div>
  );
}
