/** WebKit scroll/VT quirks — Safari and every iOS browser (all use WebKit). */
export function hasWebKitScrollRestoreQuirk(): boolean {
  return isIosSafariFamily();
}

/** iOS Safari/WebView and desktop Safari — scroll restoration + UA visual transitions. */
export function isIosSafariFamily(): boolean {
  if (typeof navigator === 'undefined') return false;
  const ua = navigator.userAgent;
  const isIos = /iP(ad|hone|od)/.test(ua);
  const isSafari = /Safari/i.test(ua) && !/Chrome|CriOS|FxiOS|EdgiOS/i.test(ua);
  return isIos || isSafari;
}

/** Prefer Apple Maps deep links on iPhone/iPad. */
export function prefersAppleMaps(): boolean {
  if (typeof navigator === 'undefined') return false;
  return /iP(ad|hone|od)/.test(navigator.userAgent);
}

export function setScrollRestoration(mode: ScrollRestoration): void {
  if (typeof history !== 'undefined' && 'scrollRestoration' in history) {
    history.scrollRestoration = mode;
  }
}

export function prefersReducedMotion(): boolean {
  if (typeof window === 'undefined' || typeof window.matchMedia !== 'function') {
    return false;
  }
  return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}
