import React from 'react';
import { useNavigate } from 'react-router';

import { EventWithDetails } from '../models/types';
import { getCountryFlag } from '../utils/dataUtils';
import { navTransition } from '../utils/navTransition';
import { getVenueStripeColor } from '../utils/venueColors';
import { FavoriteStarButton } from './FavoriteStarButton';
import { FootprintButton } from './FootprintButton';
import { useFavorites } from '../utils/useFavorites';
import { VenueMapsLink } from './VenueMapsLink';
interface EventCardProps {
  event: EventWithDetails;
  showFavoriteButton?: boolean;
  sourceInfo?: { name: string };
  clickable?: boolean;
}

export function EventCard({ event, showFavoriteButton = true, clickable = true, sourceInfo }: EventCardProps) {
  const { isFavorite, toggleFavorite, isFootprint, toggleFootprint } = useFavorites();
  const isFav = isFavorite(event.id);
  const isGoing = isFootprint(event.id);
  const navigate = useNavigate();

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
    });
  };

  const handleFavoriteToggle = (e: React.MouseEvent) => {
    e.stopPropagation();
    toggleFavorite(event.id);
  };

  const handleFootprintToggle = (e: React.MouseEvent) => {
    e.stopPropagation();
    toggleFootprint(event.id);
  };

  const handleCardClick = () => {
    let url = `/band/${event.band.id}`;
    if (sourceInfo) {
      const params = new URLSearchParams({
        fromName: sourceInfo.name,
      });
      url += `?${params.toString()}`;
    }
    navigate(url, navTransition);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if (!clickable) return;
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleCardClick();
    }
  };

  const venueStripeColor = getVenueStripeColor(event.locationId);

  return (
    <div
      className={`card mb-2 md:mb-4 border-l-4 ${isFav ? 'card--faved' : ''} ${isGoing ? 'card--planned' : ''} ${clickable ? 'cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wgt-red/70 focus-visible:ring-offset-2 focus-visible:ring-offset-wgt-void' : ''}`}
      style={{ borderLeftColor: venueStripeColor }}
      title={`Venue: ${event.location.name}`}
      onClick={clickable ? handleCardClick : undefined}
      onKeyDown={clickable ? handleKeyDown : undefined}
      role={clickable ? 'button' : undefined}
      tabIndex={clickable ? 0 : undefined}
    >
      <div className="flex justify-between items-start gap-2">
        <div className="flex-1 min-w-0">
          <div className="flex flex-wrap items-center gap-2">
            <h3 className="text-l md:text-xl font-semibold text-white">
              {event.band.name}
              {event.band.country && (
                <span className="ml-2" title={`Country: ${event.band.country}`}>
                  {getCountryFlag(event.band.country)}
                </span>
              )}
            </h3>
            {isFav && (
              <span className="schedule-pick-pill shrink-0" title="In my schedule">
                fav
              </span>
            )}
            {isGoing && (
              <span className="schedule-plan-pill shrink-0" title="Planned pick">
                going
              </span>
            )}
          </div>
          {(event.band.genre || event.band.description) && (
            <p className="text-sm text-wgt-muted truncate">
              {event.band.genre}
              {event.band.description && `${event.band.genre ? ' - ' : ''} ${event.band.description}`}
            </p>
          )}
        </div>
        {showFavoriteButton && (
          <div className="flex shrink-0 items-center gap-0.5">
            <FootprintButton
              active={isGoing}
              disabled={!isFav}
              animateOnToggle
              onClick={handleFootprintToggle}
            />
            <FavoriteStarButton filled={isFav} onClick={handleFavoriteToggle} animateOnToggle />
          </div>
        )}
      </div>

      <div className="text-sm md:text-base mt-1 md:mt-3 text-gray-300">
        <p className="flex items-center">
          <span className="inline-block w-20 text-wgt-muted">Date:</span>
          {formatDate(event.date)}
        </p>
        <p className="flex items-center">
          <span className="inline-block w-20 text-wgt-muted">Time:</span>
          {event.startTime}
          {event.endTime ? ` - ${event.endTime}` : ''}
        </p>
        <p className="flex items-center flex-wrap">
          <span className="inline-block w-20 text-wgt-muted shrink-0">Venue:</span>
          <span className="truncate md:overflow-visible">{event.location.name}</span>
          <VenueMapsLink location={event.location} />
        </p>
        {event.location.address && (
          <p className="text-sm text-wgt-muted/80 ml-20">
            {event.location.address}, {event.location.city}
          </p>
        )}
      </div>
    </div>
  );
}
