import type { Router } from 'react-router';

import { installUAVisualTransitionDetection } from './uaVisualTransition';
import { installNavigationDirection, installViewTransitionPatch } from './viewTransitions';

/** Client-side navigation: UA gesture detection, direction/scroll stamps, view transitions. */
export function installClientNavigation(router: Router): void {
  installUAVisualTransitionDetection();
  installNavigationDirection(router);
  installViewTransitionPatch();
}
