import React, { useRef, useEffect } from 'react';
import { NavLink } from 'react-router';

import faviconUrl from '../assets/favicon.svg';
import { navTransition } from '../utils/navTransition';
import { usePWAUpdate } from '../utils/usePWAUpdate';
import { useNavigationSearch } from '../context/NavigationSearch';
import { useFavorites } from '../utils/useFavorites';

const navItemClass = ({ isActive }: { isActive: boolean }) =>
  `inline-block pb-0.5 transition-colors duration-200 ${
    isActive
      ? 'text-wgt-fog font-semibold border-b-2 border-wgt-red drop-shadow-[0_0_10px_rgba(196,60,60,0.35)]'
      : 'text-wgt-muted hover:text-wgt-fog'
  }`;

export function Header() {
  const { updateAvailable, checkForUpdate, installUpdate } = usePWAUpdate();
  const { count: favoritesCount } = useFavorites();
  const inputRef = useRef<HTMLInputElement>(null);
  const { query, setQuery, panelOpen, togglePanel, closePanel } = useNavigationSearch();

  useEffect(() => {
    if (!panelOpen) return;
    const frame = requestAnimationFrame(() => inputRef.current?.focus({ preventScroll: true }));
    return () => cancelAnimationFrame(frame);
  }, [panelOpen]);

  const hasSearchQuery = query.trim().length > 0;
  const searchActive = panelOpen || hasSearchQuery;

  const searchButtonClass = searchActive
    ? 'text-wgt-fog bg-wgt-red/25 ring-2 ring-wgt-red shadow-[0_0_12px_rgba(196,60,60,0.4)]'
    : 'text-wgt-muted ring-1 ring-white/10 hover:text-wgt-fog hover:bg-wgt-slate/80 hover:ring-white/20';

  const searchButtonTitle = panelOpen
    ? 'Search open — type to filter events'
    : hasSearchQuery
      ? `Search active (“${query.trim()}”) — tap to edit`
      : 'Search bands, genres, venues, times…';

  return (
    <header className="shrink-0 z-50 border-b border-white/10 bg-wgt-ink/95 backdrop-blur-md shadow-[0_8px_32px_rgba(0,0,0,0.35)] relative">
      <div className="container mx-auto px-4 py-4">
        <div className="flex flex-col gap-4 md:flex-row md:flex-nowrap md:items-center md:justify-between md:gap-6">
          <div className="flex items-center gap-3 shrink-0">
            <NavLink
              to="/"
              end
              {...navTransition}
              className="flex items-center gap-3 text-2xl text-wgt-fog hover:text-wgt-red-glow transition-colors"
            >
              <img
                src={faviconUrl}
                alt=""
                className="hidden md:block w-8 h-8"
                width="32"
                height="32"
              />
              <span className="font-display tracking-tight">WGT web app</span>
            </NavLink>
          </div>

          <div className="flex flex-nowrap items-center justify-between gap-x-4 sm:gap-x-6 md:justify-end md:flex-1 md:min-w-0">
            <nav className="flex-1 md:flex-none min-w-0" aria-label="Main">
              <ul className="flex flex-nowrap gap-x-5 sm:gap-x-6">
                <li>
                  <NavLink to="/" end {...navTransition} className={navItemClass}>
                    Home
                  </NavLink>
                </li>
                <li>
                  <NavLink to="/schedule" {...navTransition} className={navItemClass}>
                    Schedule
                  </NavLink>
                </li>
                <li>
                  <NavLink to="/favorites" {...navTransition} className={navItemClass} title="Favorites">
                    <span className="inline-flex items-center gap-1.5 leading-none">
                      <span>Favs</span>
                      {favoritesCount > 0 && (
                        <span
                          className={`nav-schedule-count${favoritesCount < 10 ? ' nav-schedule-count--single' : ''}`}
                          aria-label={`${favoritesCount} favorites`}
                        >
                          {favoritesCount}
                        </span>
                      )}
                    </span>
                  </NavLink>
                </li>
              </ul>
            </nav>

            <div className="flex items-center gap-2 shrink-0 ml-auto md:ml-0">
              <button
                type="button"
                onClick={(e) => {
                  e.stopPropagation();
                  togglePanel();
                }}
                className={`relative p-2 rounded-lg transition-all duration-200 ${searchButtonClass}`}
                title={searchButtonTitle}
                aria-label={searchButtonTitle}
                aria-expanded={panelOpen}
                aria-pressed={searchActive}
                aria-controls="nav-search-panel"
              >
                <svg
                  className="w-5 h-5"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth={searchActive ? 2.5 : 2}
                  viewBox="0 0 24 24"
                  aria-hidden
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M21 21l-4.35-4.35M11 18a7 7 0 110-14 7 7 0 010 14z"
                  />
                </svg>
                {hasSearchQuery && (
                  <span
                    className="absolute -top-0.5 -right-0.5 flex h-2.5 w-2.5 rounded-full bg-wgt-red-glow ring-2 ring-wgt-ink"
                    aria-hidden
                  />
                )}
              </button>

              <button
                type="button"
                onClick={updateAvailable ? installUpdate : checkForUpdate}
                className={`relative p-2 rounded-lg transition-colors ${
                  updateAvailable
                    ? 'bg-wgt-red text-white hover:bg-wgt-red-glow shadow-md ring-1 ring-white/10'
                    : 'text-wgt-muted hover:text-wgt-fog hover:bg-wgt-slate/80'
                }`}
                title={updateAvailable ? 'Install update' : 'Check for updates'}
              >
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                  <path
                    fillRule="evenodd"
                    d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 010 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z"
                    clipRule="evenodd"
                  />
                </svg>
                {updateAvailable && (
                  <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full w-3 h-3" />
                )}
              </button>
            </div>
          </div>
        </div>
      </div>

      {panelOpen && (
        <div
          id="nav-search-panel"
          className="border-t border-wgt-red/30 bg-wgt-ink/98 backdrop-blur-md shadow-[inset_0_1px_0_rgba(196,60,60,0.25)]"
          onClick={(e) => e.stopPropagation()}
          role="search"
        >
          <div className="container mx-auto px-4 py-3 flex gap-3 items-center">
            <svg
              className="w-5 h-5 text-wgt-muted shrink-0 pointer-events-none"
              fill="none"
              stroke="currentColor"
              strokeWidth={2}
              viewBox="0 0 24 24"
              aria-hidden
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M21 21l-4.35-4.35M11 18a7 7 0 110-14 7 7 0 010 14z"
              />
            </svg>
            <input
              ref={inputRef}
              id="nav-search-input"
              type="search"
              enterKeyHint="search"
              autoComplete="off"
              aria-label="Search events"
              className="flex-1 min-w-0 bg-wgt-slate/55 text-wgt-fog placeholder:text-wgt-muted/75 rounded-lg px-3 py-2 border border-white/12 focus:border-wgt-purple/40 focus:outline-none focus:ring-1 focus:ring-wgt-purple/30"
              placeholder="Bands, genres, venues, times…"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
            <button
              type="button"
              className="text-sm text-wgt-muted hover:text-wgt-fog px-3 py-2 rounded-lg hover:bg-wgt-slate/70 shrink-0"
              title="Clear search text"
              onClick={() => setQuery('')}
              aria-label="Clear search text"
            >
              Clear
            </button>
            <button
              type="button"
              className="text-wgt-muted hover:text-wgt-fog p-2 rounded-lg hover:bg-wgt-slate/70 shrink-0 border border-transparent hover:border-white/10"
              onClick={() => closePanel()}
              aria-label="Close search"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
      )}
    </header>
  );
}
