import React, { useState } from 'react';
import { Link } from 'react-router';

import { navTransition } from '../utils/navTransition';

const linkClass =
  'text-wgt-muted/90 hover:text-wgt-fog transition-colors';

export function Footer() {
  const currentYear = new Date().getFullYear();
  const [showBuildInfo, setShowBuildInfo] = useState(false);

  const version = typeof __APP_VERSION__ !== 'undefined' ? __APP_VERSION__ : 'dev';
  const buildTime =
    typeof __BUILD_TIME__ !== 'undefined' ? __BUILD_TIME__ : new Date().toISOString();

  return (
    <footer className="shrink-0 border-t border-white/10 bg-wgt-ink/95 backdrop-blur-md shadow-[0_-4px_24px_rgba(0,0,0,0.25)]">
      <div className="container mx-auto px-4 py-3">
        <div className="flex flex-wrap items-center justify-center gap-x-3 gap-y-1 text-sm text-wgt-muted">
          <span className="whitespace-nowrap">&copy; {currentYear} WGT</span>
          <span className="text-white/20" aria-hidden>
            ·
          </span>
          <a
            href="https://www.wave-gotik-treffen.de/"
            target="_blank"
            rel="noopener noreferrer"
            className={linkClass}
          >
            WGT.de
          </a>
          <span className="text-white/20" aria-hidden>
            ·
          </span>
          <Link to="/impressum" {...navTransition} className={linkClass}>
            Impressum
          </Link>
          <span className="text-white/20" aria-hidden>
            ·
          </span>
          <button
            type="button"
            onClick={() => setShowBuildInfo(true)}
            className={`${linkClass} bg-transparent border-0 p-0 cursor-pointer font-inherit`}
            title="Build information"
          >
            v{version}
          </button>
        </div>
      </div>

      {showBuildInfo && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4"
          onClick={() => setShowBuildInfo(false)}
        >
          <div
            className="max-w-md rounded-lg bg-white p-6"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="mb-4 text-lg font-semibold text-gray-800">Build Information</h3>
            <div className="space-y-2 text-sm text-gray-600">
              <div className="flex justify-between">
                <span className="font-medium">Version:</span>
                <span className="font-mono">{version}</span>
              </div>
              <div className="flex justify-between">
                <span className="font-medium">Build Time:</span>
                <span className="font-mono text-xs">
                  {new Date(buildTime).toLocaleString()}
                </span>
              </div>
              <div className="flex justify-between">
                <span className="font-medium">Framework:</span>
                <span>React + React Router + Vite</span>
              </div>
              <div className="flex justify-between">
                <span className="font-medium">PWA:</span>
                <span>Enabled</span>
              </div>
            </div>
            <button
              type="button"
              onClick={() => setShowBuildInfo(false)}
              className="mt-4 w-full rounded bg-gray-800 px-4 py-2 text-white transition-colors hover:bg-gray-700"
            >
              Close
            </button>
          </div>
        </div>
      )}
    </footer>
  );
}
