import React, { useState, useEffect, useMemo } from 'react';

import type { Schedule as ScheduleType, EventWithDetails, FacetFilterOptions } from '../models/types';
import { EMPTY_FACET_FILTERS } from '../models/types';
import {
  buildScheduleSnapshot,
  getCachedScheduleSnapshot,
  loadScheduleData,
  isScheduleLoaded,
} from '../utils/apiUtils';
import { filterEventsWithNavSearch, loadFilters, saveFilters } from '../utils/dataUtils';
import { groupEventsByDate } from '../utils/scheduleUtils';
import { EventFilter } from '../components/EventFilter';
import { DayGroup } from '../components/DayGroup';
import { SkeletonLoader } from '../components/SkeletonLoader';
import { ErrorMessage } from '../components/ErrorMessage';
import { loadDayGroupStates, toggleDayExpanded, isDayExpanded } from '../utils/dayGroupUtils';
import { useNavigationSearch } from '../context/NavigationSearch';
import { useScrollToTopOnNavSearchChange } from '../hooks/useScrollToTopOnNavSearchChange';
import { useFavorites } from '../utils/useFavorites';

const cachedSchedule = getCachedScheduleSnapshot();

export function Schedule() {
  const [schedule, setSchedule] = useState<ScheduleType | null>(cachedSchedule?.schedule ?? null);
  const [events, setEvents] = useState<EventWithDetails[]>(cachedSchedule?.events ?? []);
  const [loading, setLoading] = useState(!isScheduleLoaded());
  const [error, setError] = useState<string | null>(null);
  const [uniqueDates, setUniqueDates] = useState<string[]>(cachedSchedule?.uniqueDates ?? []);
  const [expandedDays, setExpandedDays] = useState<Record<string, boolean>>(() => loadDayGroupStates());
  const [facetFilters, setFacetFilters] = useState<FacetFilterOptions>(
    () => loadFilters() ?? EMPTY_FACET_FILTERS,
  );

  const { query: navSearchQuery } = useNavigationSearch();
  const { count: favoritesCount } = useFavorites();
  useScrollToTopOnNavSearchChange();

  const filteredEvents = useMemo(
    () => filterEventsWithNavSearch(events, facetFilters, navSearchQuery),
    [events, facetFilters, navSearchQuery, favoritesCount],
  );

  useEffect(() => {
    let cancelled = false;

    async function fetchData() {
      try {
        const data = await loadScheduleData();
        if (cancelled) return;

        const snapshot = buildScheduleSnapshot(data);
        setSchedule(snapshot.schedule);
        setEvents(snapshot.events);
        setUniqueDates(snapshot.uniqueDates);
      } catch (err) {
        if (!cancelled) {
          setError('Failed to load schedule data. Please try again later.');
          console.error(err);
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    }

    fetchData();
    return () => {
      cancelled = true;
    };
  }, []);

  const handleFacetChange = (facets: FacetFilterOptions) => {
    setFacetFilters(facets);
    saveFilters(facets);
  };

  const handleToggleDayExpanded = (date: string) => {
    setExpandedDays(toggleDayExpanded(date, expandedDays));
  };

  const isExpanded = (date: string) => isDayExpanded(date, expandedDays);

  if (loading) {
    return <SkeletonLoader message="Loading schedule data..." showDays={true} itemCount={3} />;
  }

  if (error) {
    return <ErrorMessage message={error} />;
  }

  return (
    <div className="schedule-page">
      <h1 className="font-display text-3xl md:text-4xl text-wgt-fog mb-6">Festival Schedule</h1>

      {schedule && (
        <div className="schedule-sticky-filters sticky top-0 z-40 border-b border-white/5 bg-wgt-void/90 backdrop-blur-md pb-2 -mx-4 px-4 sm:-mx-6 sm:px-6 md:-mx-8 md:px-8">
          <EventFilter
            onFilterChange={handleFacetChange}
            locations={schedule.locations}
            dates={uniqueDates}
            initialFilters={facetFilters}
            showMyPicksToggle
          />
        </div>
      )}

      {filteredEvents.length > 0 ? (
        <div className="schedule-day-groups">
          {Object.entries(groupEventsByDate(filteredEvents))
            .sort(([a], [b]) => a.localeCompare(b))
            .map(([date, dayEvents]) => (
              <DayGroup
                key={date}
                date={date}
                events={dayEvents}
                isExpanded={isExpanded(date)}
                onToggleExpanded={handleToggleDayExpanded}
                sourceInfo={{ name: 'Schedule' }}
              />
            ))}
        </div>
      ) : (
        <div className="card text-center py-8">
          <p className="text-xl text-wgt-muted">No events found matching your filters.</p>
          <p className="text-wgt-muted/80 mt-2">Try adjusting facets or clearing the nav search.</p>
        </div>
      )}
    </div>
  );
}
