import React from 'react';
import { EventWithDetails } from '../models/types';
import { EventCard } from './EventCard';
import { DayHeader } from './DayHeader';
import { TravelBetweenEvents } from './TravelBetweenEvents';
import { interleaveTravelHints } from '../utils/mapUtils';

interface DayGroupProps {
  date: string;
  events: EventWithDetails[];
  isExpanded: boolean;
  onToggleExpanded: (date: string) => void;
  sourceInfo?: { name: string };
  showFavoriteButton?: boolean;
  showTravelHints?: boolean;
}

export function DayGroup({
  date,
  events,
  isExpanded,
  onToggleExpanded,
  sourceInfo,
  showFavoriteButton = true,
  showTravelHints = false,
}: DayGroupProps) {
  const scheduleItems = showTravelHints ? interleaveTravelHints(events) : events.map((event) => ({ type: 'event' as const, event }));

  return (
    <div className="mb-4 md:mb-8">
      <DayHeader 
        date={date}
        eventCount={events.length}
        isExpanded={isExpanded}
        onToggle={onToggleExpanded}
      />
      {isExpanded && (
        <div className="space-y-2 mt-2">
          {scheduleItems.map((item, index) => {
            if (item.type === 'event') {
              return (
                <EventCard
                  key={item.event.id}
                  event={item.event}
                  showFavoriteButton={showFavoriteButton}
                  sourceInfo={sourceInfo}
                />
              );
            }

            return (
              <TravelBetweenEvents
                key={`travel-${item.from.id}-${item.to.id}-${index}`}
                from={item.from}
                to={item.to}
                nextStartTime={item.nextStartTime}
              />
            );
          })}
        </div>
      )}
    </div>
  );
} 