import React, { useState, useEffect } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router';

import { Band, EventWithDetails } from '../models/types';
import { loadScheduleData, isScheduleLoaded } from '../utils/apiUtils';
import { findBandById, findEventsByBandId, sortEventsByDateTime } from '../utils/dataUtils';
import { EventCard } from '../components/EventCard';
import { SkeletonLoader } from '../components/SkeletonLoader';
import { navigateBack } from '../utils/navTransition';
export function BandDetail() {
  const { id = '' } = useParams<{ id: string }>();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const fromName = searchParams.get('fromName') ?? undefined;

  const [band, setBand] = useState<Band | null>(null);
  const [events, setEvents] = useState<EventWithDetails[]>([]);
  const [loading, setLoading] = useState(!isScheduleLoaded());
  const [error, setError] = useState<string | null>(null);

  const backLink = {
    name: fromName ? decodeURIComponent(fromName) : 'Schedule'
  };

  const handleBackClick = () => {
    navigateBack(navigate);
  };

  useEffect(() => {
    async function fetchData() {
      try {
        const data = await loadScheduleData();

        const bandData = findBandById(id, data);
        if (!bandData) {
          setError('Band not found');
          setLoading(false);
          return;
        }

        setBand(bandData);

        const bandEvents = findEventsByBandId(id, data);
        setEvents(sortEventsByDateTime(bandEvents));
      } catch (err) {
        setError('Failed to load band data. Please try again later.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    }

    if (id) {
      fetchData();
    }
  }, [id]);

  if (!id) {
    return (
      <div className="border border-wgt-red/50 bg-wgt-red/15 text-wgt-fog p-4 rounded-xl">
        <h2 className="font-display text-xl mb-2">Error</h2>
        <p>Missing band id</p>
      </div>
    );
  }

  if (loading) {
    return <SkeletonLoader message="Loading band information..." showDays={false} itemCount={2} />;
  }

  if (error || !band) {
    return (
      <div className="border border-wgt-red/50 bg-wgt-red/15 text-wgt-fog p-4 rounded-xl">
        <h2 className="font-display text-xl mb-2">Error</h2>
        <p>{error || 'Band not found'}</p>
        <button type="button" onClick={handleBackClick} className="btn btn-primary mt-4">
          Back to {backLink.name}
        </button>
      </div>
    );
  }

  return (
    <div>
      <button type="button" onClick={handleBackClick} className="text-wgt-muted hover:text-wgt-fog mb-4 inline-block bg-transparent border-none cursor-pointer">
        ← Back to {backLink.name}
      </button>

      <div className="card mb-6">
        <h1 className="font-display text-3xl md:text-4xl text-wgt-fog mb-2">{band.name}</h1>

        {band.genre && (
          <p className="text-wgt-muted mb-4">{band.genre}</p>
        )}

        {band.description && (
          <div className="mt-4">
            <h2 className="font-display text-xl mb-2">About</h2>
            <p className="text-wgt-fog/90 leading-relaxed">{band.description}</p>
          </div>
        )}
      </div>

      <div className="mt-8">
        <h2 className="font-display text-2xl md:text-3xl mb-4 text-wgt-fog">Performances</h2>

        {events.length > 0 ? (
          <div>
            {events.map(event => (
              <EventCard key={event.id} event={event} sourceInfo={{ name: `${band.name} Details`}} clickable={false} />
            ))}
          </div>
        ) : (
          <div className="card text-center py-8">
            <p className="text-xl text-wgt-muted">No performances scheduled for this band.</p>
          </div>
        )}
      </div>

      {band.description && (
        <div className="mt-8 pt-4 border-t border-white/10">
          <p className="text-xs text-wgt-muted text-center">
            Band description sourced from{' '}
            <a
              href="https://www.discogs.com"
              target="_blank"
              rel="noopener noreferrer"
              className="text-wgt-fog/80 hover:text-wgt-fog underline"
            >
              Discogs.com
            </a>
          </p>
        </div>
      )}
    </div>
  );
}
