import React from 'react';
import { useNavigate } from 'react-router';

import { EventWithDetails } from '../models/types';
import { FavoriteStarButton } from './FavoriteStarButton';
import { FootprintButton } from './FootprintButton';
import { TravelBetweenEvents } from './TravelBetweenEvents';
import { getGapBeforeEvent, getPickConflictLevels } from '../utils/scheduleTimelineUtils';
import { getVenueStripeColor } from '../utils/venueColors';
import { useFavorites } from '../utils/useFavorites';
import { navTransition } from '../utils/navTransition';
import { VenueMapsLink } from './VenueMapsLink';

interface FavoritesTimelineProps {
  events: EventWithDetails[];
  sourceInfo?: { name: string };
  showConflicts?: boolean;
  showTravelHints?: boolean;
}

export function FavoritesTimeline({
  events,
  sourceInfo,
  showConflicts = false,
  showTravelHints = false,
}: FavoritesTimelineProps) {
  const navigate = useNavigate();
  const { isFavorite, toggleFavorite, isFootprint, toggleFootprint } = useFavorites();
  const sorted = [...events].sort((a, b) => a.startTime.localeCompare(b.startTime));
  const planned = sorted.filter((event) => isFootprint(event.id));
  const conflictLevels = showConflicts ? getPickConflictLevels(planned) : null;

  const openBand = (event: EventWithDetails) => {
    let url = `/band/${event.band.id}`;
    if (sourceInfo) {
      url += `?${new URLSearchParams({ fromName: sourceInfo.name }).toString()}`;
    }
    navigate(url, navTransition);
  };

  return (
    <ol className="schedule-timeline list-none m-0 p-0">
      {sorted.map((event, index) => {
        const gap = getGapBeforeEvent(sorted, index);
        const plannedPick = isFootprint(event.id);
        const conflict = plannedPick ? conflictLevels?.get(event.id) : undefined;
        const stripe = getVenueStripeColor(event.locationId);
        const endLabel = event.endTime ? ` – ${event.endTime}` : '';
        const previous = sorted[index - 1];
        const showTravel =
          showTravelHints &&
          previous != null &&
          previous.locationId !== event.locationId;

        const hasClash = showConflicts && conflict === 'clash';
        const hasSqueeze = showConflicts && conflict === 'squeeze';

        return (
          <li key={event.id} className="schedule-timeline__item">
            {showTravel && (
              <TravelBetweenEvents
                from={previous.location}
                to={event.location}
                nextStartTime={event.startTime}
              />
            )}
            {gap && (
              <div className="schedule-timeline__gap" aria-hidden="true">
                <span>{gap}</span>
              </div>
            )}
            <div
              className={`schedule-timeline__row${
                plannedPick && !hasClash && !hasSqueeze ? ' schedule-timeline__row--planned' : ''
              }${hasClash ? ' schedule-timeline__row--clash' : ''}${
                hasSqueeze ? ' schedule-timeline__row--squeeze' : ''
              }`}
              style={{ '--venue-stripe': stripe } as React.CSSProperties}
            >
              <div className="schedule-timeline__time">
                <span className="schedule-timeline__start">{event.startTime}</span>
                {event.endTime && (
                  <span className="schedule-timeline__end">{endLabel}</span>
                )}
              </div>
              <div className="schedule-timeline__body">
                <button
                  type="button"
                  className="schedule-timeline__pick w-full text-left cursor-pointer focus-visible:outline-none"
                  onClick={() => openBand(event)}
                >
                  <div className="flex flex-wrap items-center gap-2 min-w-0">
                    <span className="schedule-timeline__band">{event.band.name}</span>
                    <span className="schedule-pick-pill shrink-0">fav</span>
                    {plannedPick && (
                      <span className="schedule-plan-pill shrink-0" title="Planned pick">
                        going
                      </span>
                    )}
                    {hasClash && (
                      <span
                        className="schedule-timeline__clash-badge"
                        title="Overlaps another planned pick — hard to do both"
                      >
                        clash
                      </span>
                    )}
                    {hasSqueeze && (
                      <span
                        className="schedule-timeline__squeeze-badge"
                        title="Tight window with another planned pick"
                      >
                        squeeze
                      </span>
                    )}
                  </div>
                  {event.band.genre && (
                    <span className="schedule-timeline__genre">{event.band.genre}</span>
                  )}
                </button>
                <div className="schedule-timeline__venue">
                  {event.location.name}
                  <VenueMapsLink location={event.location} />
                </div>
              </div>
              <div className="flex shrink-0 items-center gap-0.5">
                <FootprintButton
                  size="sm"
                  active={plannedPick}
                  disabled={!isFavorite(event.id)}
                  animateOnToggle
                  onClick={(e) => {
                    e.stopPropagation();
                    toggleFootprint(event.id);
                  }}
                />
                <FavoriteStarButton
                  size="sm"
                  filled={isFavorite(event.id)}
                  animateOnToggle
                  onClick={(e) => {
                    e.stopPropagation();
                    toggleFavorite(event.id);
                  }}
                />
              </div>
            </div>
          </li>
        );
      })}
    </ol>
  );
}
