/**
 * Stable venue colors for list cards (Schedule, Favorites).
 * Same locationId always maps to the same stripe color.
 */
const VENUE_STRIPE_COLORS = [
  '#c45c5c', // red
  '#5b8fd4', // blue
  '#6ab87a', // green
  '#c9a227', // gold
  '#9b6bb8', // purple
  '#d4845c', // orange
  '#4db8b8', // teal
  '#b87aa0', // rose
  '#8a9b5c', // olive
  '#7a8fd4', // periwinkle
  '#c47a9b', // pink
  '#5c9b8a', // sea
  '#b8a04d', // amber
  '#8fc45c', // lime
] as const;

function hashLocationId(locationId: string): number {
  let hash = 0;
  for (let i = 0; i < locationId.length; i++) {
    hash = (hash * 31 + locationId.charCodeAt(i)) >>> 0;
  }
  return hash;
}

export function getVenueStripeColor(locationId: string): string {
  const index = hashLocationId(locationId) % VENUE_STRIPE_COLORS.length;
  return VENUE_STRIPE_COLORS[index];
}
