import { useEffect, useRef } from 'react';
import { useLocation } from 'react-router';

import { useNavigationSearch } from '../context/NavigationSearch';
import { savePageScrollForPath, scrollPageToTop } from '../utils/pageScroll';

/** When nav search text changes, scroll the page pane to top and stamp saved scroll at 0 for this route. */
export function useScrollToTopOnNavSearchChange(): void {
  const { query } = useNavigationSearch();
  const { pathname } = useLocation();
  const prevQuery = useRef<string | undefined>(undefined);

  useEffect(() => {
    if (prevQuery.current === undefined) {
      prevQuery.current = query;
      return;
    }
    if (prevQuery.current === query) {
      return;
    }
    prevQuery.current = query;
    requestAnimationFrame(() => {
      scrollPageToTop();
      savePageScrollForPath(pathname);
    });
  }, [query, pathname]);
}
