import React, { useState, useEffect, useMemo } from 'react';
import { Link, useSearchParams } from 'react-router';

import type { Schedule, EventWithDetails, FacetFilterOptions } from '../models/types';
import { EMPTY_FACET_FILTERS } from '../models/types';
import { loadScheduleData, isScheduleLoaded } from '../utils/apiUtils';
import {
  getAllEventsWithDetails,
  sortEventsByDateTime,
  decodeSharedSchedule,
  addFavorite,
  filterEventsWithNavSearch,
} from '../utils/dataUtils';
import { groupEventsByDate } from '../utils/scheduleUtils';
import { DayGroup } from '../components/DayGroup';
import { EventFilter } from '../components/EventFilter';
import { SkeletonLoader } from '../components/SkeletonLoader';
import { navTransition } from '../utils/navTransition';
import { loadDayGroupStates, toggleDayExpanded, isDayExpanded } from '../utils/dayGroupUtils';
import { useNavigationSearch } from '../context/NavigationSearch';
import { useScrollToTopOnNavSearchChange } from '../hooks/useScrollToTopOnNavSearchChange';

export function SharedSchedule() {
  const [searchParams] = useSearchParams();
  const encodedSchedule = searchParams.get('schedule') ?? undefined;

  const [schedule, setSchedule] = useState<Schedule | null>(null);
  const [sharedEvents, setSharedEvents] = useState<EventWithDetails[]>([]);
  const [uniqueDates, setUniqueDates] = useState<string[]>([]);
  const [expandedDays, setExpandedDays] = useState<Record<string, boolean>>({});
  const [facetFilters, setFacetFilters] = useState<FacetFilterOptions>(EMPTY_FACET_FILTERS);
  const [loading, setLoading] = useState(!isScheduleLoaded());
  const [error, setError] = useState<string | null>(null);
  const [imported, setImported] = useState(false);

  const { query: navSearchQuery } = useNavigationSearch();
  useScrollToTopOnNavSearchChange();

  const filteredEvents = useMemo(
    () => filterEventsWithNavSearch(sharedEvents, facetFilters, navSearchQuery),
    [sharedEvents, facetFilters, navSearchQuery],
  );

  useEffect(() => {
    setExpandedDays(loadDayGroupStates());
  }, []);

  useEffect(() => {
    async function fetchData() {
      try {
        if (!encodedSchedule) {
          setError('No schedule data provided');
          setLoading(false);
          return;
        }

        const data = await loadScheduleData();
        setSchedule(data);

        const eventIds = decodeSharedSchedule(encodedSchedule);
        if (eventIds.length === 0) {
          setError('Invalid schedule data');
          setLoading(false);
          return;
        }

        const allEvents = getAllEventsWithDetails(data);
        const events = allEvents.filter((event) => eventIds.includes(event.id));
        const sortedEvents = sortEventsByDateTime(events);

        setSharedEvents(sortedEvents);

        const dates = Array.from(new Set(sortedEvents.map((event) => event.date)));
        setUniqueDates(dates);
      } catch (err) {
        setError('Failed to load shared schedule. Please try again later.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [encodedSchedule]);

  const handleImportToFavorites = () => {
    sharedEvents.forEach((event) => {
      addFavorite(event.id);
    });
    setImported(true);
  };

  const handleFacetChange = (filters: FacetFilterOptions) => {
    setFacetFilters(filters);
  };

  const handleToggleDayExpanded = (date: string) => {
    setExpandedDays(toggleDayExpanded(date, expandedDays));
  };

  const isExpanded = (date: string) => isDayExpanded(date, expandedDays);

  if (loading) {
    return <SkeletonLoader message="Loading shared schedule..." showDays={false} itemCount={3} />;
  }

  if (error) {
    return (
      <div className="bg-red-900 text-white p-4 rounded-lg">
        <h2 className="text-xl font-bold mb-2">Error</h2>
        <p>{error}</p>
        <Link to="/" {...navTransition} className="btn btn-primary mt-4 inline-block">
          Go to Home
        </Link>
      </div>
    );
  }

  return (
    <div>
      <div className="flex flex-col md:flex-row md:justify-between md:items-center mb-6">
        <h1 className="font-display text-3xl md:text-4xl text-wgt-fog mb-4 md:mb-0">
          Shared Festival Schedule
        </h1>

        {sharedEvents.length > 0 && !imported && (
          <button type="button" onClick={handleImportToFavorites} className="btn btn-primary">
            Import to my schedule
          </button>
        )}

        {imported && (
          <div className="bg-green-800 text-white px-4 py-2 rounded">
            Added to your schedule!
          </div>
        )}
      </div>

      {sharedEvents.length > 0 ? (
        <div>
          {schedule && (
            <div className="sticky top-0 z-40 border-b border-white/5 bg-wgt-void/90 backdrop-blur-md pb-2 -mx-4 px-4 sm:-mx-6 sm:px-6 md:-mx-8 md:px-8 mb-4">
              <EventFilter
                onFilterChange={handleFacetChange}
                locations={schedule.locations}
                dates={uniqueDates}
                initialFilters={facetFilters}
              />
            </div>
          )}

          {filteredEvents.length > 0 ? (
            <>
              {Object.entries(groupEventsByDate(filteredEvents))
                .sort(([a], [b]) => a.localeCompare(b))
                .map(([date, dayEvents]) => (
                  <DayGroup
                    key={date}
                    date={date}
                    events={dayEvents}
                    isExpanded={isExpanded(date)}
                    onToggleExpanded={handleToggleDayExpanded}
                    showFavoriteButton={false}
                    sourceInfo={{ name: 'Shared Schedule' }}
                  />
                ))}
            </>
          ) : (
            <div className="card text-center py-8">
              <p className="text-xl text-wgt-muted">No events match your filter criteria.</p>
              <p className="text-wgt-muted/80 mt-2">Try adjusting facets or clearing the nav search.</p>
            </div>
          )}

          <div className="mt-8 flex justify-center">
            <Link to="/favorites" {...navTransition} className="btn btn-secondary">
              View my schedule
            </Link>
          </div>
        </div>
      ) : (
        <div className="card text-center py-8">
          <p className="text-xl text-wgt-muted">No events found in the shared schedule.</p>
          <div className="mt-6">
            <Link to="/" {...navTransition} className="btn btn-primary">
              Go to Home
            </Link>
          </div>
        </div>
      )}
    </div>
  );
}
