import React, { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router';

import { EMPTY_FACET_FILTERS, EventWithDetails, Schedule } from '../models/types';
import {
  buildHomeSnapshot,
  getCachedHomeSnapshot,
  isScheduleLoaded,
  loadScheduleData,
} from '../utils/apiUtils';
import { filterEventsWithNavSearch } from '../utils/dataUtils';
import {
  formatPicksDayLabel,
  getDaySummary,
  type HomePicksSection,
} from '../utils/scheduleTimelineUtils';
import { EventCard } from '../components/EventCard';
import { FavoritesTimeline } from '../components/FavoritesTimeline';
import { navTransition } from '../utils/navTransition';
import { SkeletonLoader } from '../components/SkeletonLoader';
import { useNavigationSearch } from '../context/NavigationSearch';
import { useScrollToTopOnNavSearchChange } from '../hooks/useScrollToTopOnNavSearchChange';
import motifDividerUrl from '../assets/ui/motif-divider.svg';

const cachedHome = getCachedHomeSnapshot();

export function Home() {
  const [_, setSchedule] = useState<Schedule | null>(cachedHome?.schedule ?? null);
  const [upcomingPool, setUpcomingPool] = useState<EventWithDetails[]>(cachedHome?.upcomingPool ?? []);
  const [homePicks, setHomePicks] = useState<HomePicksSection | null>(cachedHome?.homePicks ?? null);
  const [loading, setLoading] = useState(!isScheduleLoaded());
  const [error, setError] = useState<string | null>(null);
  const [isWelcomeExpanded, setIsWelcomeExpanded] = useState(false);

  const { query: navSearchQuery } = useNavigationSearch();
  useScrollToTopOnNavSearchChange();

  const upcomingEvents = useMemo(() => {
    const matched = filterEventsWithNavSearch(upcomingPool, EMPTY_FACET_FILTERS, navSearchQuery);
    return navSearchQuery.trim() ? matched : matched.slice(0, 5);
  }, [upcomingPool, navSearchQuery]);

  useEffect(() => {
    const hasVisited = localStorage.getItem('wgt-guide-visited');
    if (!hasVisited) {
      setIsWelcomeExpanded(true);
      localStorage.setItem('wgt-guide-visited', 'true');
    }
  }, []);

  useEffect(() => {
    async function fetchData() {
      try {
        const data = await loadScheduleData();
        const snapshot = buildHomeSnapshot(data);
        setSchedule(snapshot.schedule);
        setUpcomingPool(snapshot.upcomingPool);
        setHomePicks(snapshot.homePicks);
      } catch (err) {
        setError('Failed to load schedule data. Please try again later.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    }

    fetchData();

    const refreshPicks = () => {
      loadScheduleData()
        .then((data) => setHomePicks(buildHomeSnapshot(data).homePicks))
        .catch(() => {});
    };

    window.addEventListener('favoritesChanged', refreshPicks);
    return () => window.removeEventListener('favoritesChanged', refreshPicks);
  }, []);

  const toggleWelcome = () => {
    setIsWelcomeExpanded(!isWelcomeExpanded);
  };

  if (loading) {
    return <SkeletonLoader message="Loading festival data..." showDays={false} itemCount={3} />;
  }

  if (error) {
    return (
      <div className="border border-wgt-red/50 bg-wgt-red/15 text-wgt-fog p-4 rounded-xl">
        <h2 className="font-display text-xl mb-2">Error</h2>
        <p>{error}</p>
      </div>
    );
  }

  return (
    <div>
      <section className="mb-8">
        <div className="rounded-xl border border-white/6 bg-wgt-slate/25 backdrop-blur-sm shadow-[0_8px_32px_rgba(0,0,0,0.28)]">
          <div className="p-4 md:p-5">
            <div
              className="cursor-pointer flex items-center justify-between gap-3 rounded-lg w-full min-h-11 transition-colors hover:bg-white/4 focus:outline-none focus-visible:ring-2 focus-visible:ring-wgt-purple/30 focus-visible:ring-offset-2 focus-visible:ring-offset-wgt-slate/30"
              onClick={toggleWelcome}
              role="button"
              tabIndex={0}
              aria-expanded={isWelcomeExpanded}
              onKeyDown={(e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault();
                  toggleWelcome();
                }
              }}
            >
              <h1 className="text-lg md:text-xl font-semibold text-wgt-fog/90 tracking-tight leading-snug">
                Welcome to WGT web app
              </h1>
              <div className="shrink-0 text-wgt-muted" aria-hidden>
                <svg
                  className={`w-5 h-5 transform transition-transform duration-300 ${isWelcomeExpanded ? 'rotate-180' : ''}`}
                  fill="none"
                  stroke="currentColor"
                  strokeWidth={2}
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                </svg>
              </div>
            </div>
            <div
              id="welcome-panel"
              className={`transition-all duration-300 ease-in-out overflow-hidden ${isWelcomeExpanded ? 'max-h-96 opacity-100 mt-3' : 'max-h-0 opacity-0 mt-0'}`}
            >
              <div>
                <p className="text-sm md:text-base text-wgt-muted/95 mb-5 leading-relaxed">
                  Your personal guide to the Wave-Gotik-Treffen festival. Browse the program,
                  star the bands you want to see, and build your festival schedule.
                </p>
                <div className="flex flex-col sm:flex-row gap-3">
                  <Link to="/schedule" {...navTransition} className="btn btn-primary text-center text-sm md:text-base py-2.5">
                    View Full Schedule
                  </Link>
                  <Link to="/favorites" {...navTransition} className="btn btn-secondary text-center text-sm md:text-base py-2.5">
                    My schedule
                  </Link>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {homePicks && homePicks.allDayEvents.length > 0 && (
        <section className="mb-10">
          <div className="flex flex-col sm:flex-row sm:items-end sm:justify-between gap-2 mb-1">
            <h2 className="font-display text-2xl md:text-3xl text-wgt-fog">
              {homePicks.isToday
                ? 'Your picks today'
                : `Your picks · ${formatPicksDayLabel(homePicks.focusDate)}`}
            </h2>
            <Link
              to="/favorites"
              {...navTransition}
              className="text-sm text-[#d4af37] hover:text-wgt-fog transition-colors shrink-0"
            >
              View my schedule →
            </Link>
          </div>
          <p className="text-sm text-wgt-muted mb-4">{getDaySummary(homePicks.allDayEvents)}</p>
          {homePicks.events.length > 0 ? (
            <FavoritesTimeline events={homePicks.events} sourceInfo={{ name: 'Home' }} showConflicts />
          ) : (
            <p className="text-sm text-wgt-muted">
              No more picks coming up today.{' '}
              <Link to="/favorites" {...navTransition} className="text-[#d4af37] hover:text-wgt-fog">
                View full schedule
              </Link>
            </p>
          )}
        </section>
      )}

      <section className="mb-10">
        <h2 className="font-display text-2xl md:text-3xl mb-4 text-wgt-fog">Upcoming Events</h2>
        {upcomingEvents.length > 0 ? (
          <div>
            {upcomingEvents.map((event) => (
              <EventCard key={event.id} event={event} sourceInfo={{ name: 'Home' }} />
            ))}
            <div className="text-center mt-6">
              <Link to="/schedule" {...navTransition} className="btn btn-primary">
                View All Events
              </Link>
            </div>
          </div>
        ) : (
          <p className="text-wgt-muted">
            {navSearchQuery.trim()
              ? 'No upcoming events match your search.'
              : 'No upcoming events found.'}
          </p>
        )}
      </section>

      <div className="flex justify-center text-wgt-purple my-6" aria-hidden>
        <img src={motifDividerUrl} alt="" className="w-48 md:w-64 h-auto opacity-70" width="240" height="16" />
      </div>

      <section>
        <h2 className="font-display text-2xl md:text-3xl mb-4 text-wgt-fog">About Wave-Gotik-Treffen</h2>
        <div className="card">
          <p className="mb-4">
            Wave-Gotik-Treffen (WGT) is one of the largest gothic festivals in the world,
            held annually in Leipzig, Germany. The festival features a diverse range of
            music styles including gothic rock, EBM, industrial, noise, darkwave,
            neofolk, neoclassical, and various other genres.
          </p>
          <p>
            <a
              href="https://www.wave-gotik-treffen.de/"
              target="_blank"
              rel="noopener noreferrer"
              className="text-wgt-red-glow hover:text-wgt-fog underline-offset-2 hover:underline"
            >
              Visit the official WGT website →
            </a>
          </p>
        </div>
      </section>
    </div>
  );
}
