import React from 'react';

import { Location } from '../models/types';
import {
  buildAppleMapsDirectionsUrl,
  buildGoogleMapsDirectionsUrl,
} from '../utils/mapUtils';
import { prefersAppleMaps } from '../utils/platform';

interface TravelBetweenEventsProps {
  from: Location;
  to: Location;
  nextStartTime: string;
}

export function TravelBetweenEvents({ from, to, nextStartTime }: TravelBetweenEventsProps) {
  const primaryUrl = prefersAppleMaps()
    ? buildAppleMapsDirectionsUrl(from, to)
    : buildGoogleMapsDirectionsUrl(from, to);
  const primaryLabel = prefersAppleMaps() ? 'Apple Maps' : 'Google Maps';
  const secondaryUrl = prefersAppleMaps()
    ? buildGoogleMapsDirectionsUrl(from, to)
    : buildAppleMapsDirectionsUrl(from, to);
  const secondaryLabel = prefersAppleMaps() ? 'Google Maps' : 'Apple Maps';

  return (
    <div
      className="my-2 flex flex-col gap-2 rounded-lg border border-dashed border-white/15 bg-wgt-ink/60 px-3 py-2 text-sm text-wgt-muted md:flex-row md:items-center md:justify-between"
      aria-label={`Travel from ${from.name} to ${to.name}`}
    >
      <p>
        <span className="mr-1" aria-hidden="true">→</span>
        Navigate to <span className="text-wgt-fog">{to.name}</span>
        <span className="text-wgt-muted/80"> (next at {nextStartTime})</span>
      </p>
      <div className="flex flex-wrap items-center gap-2">
        <a
          href={primaryUrl}
          target="_blank"
          rel="noopener noreferrer"
          className="btn btn-secondary py-1 px-3 text-xs md:text-sm"
        >
          {primaryLabel}
        </a>
        <a
          href={secondaryUrl}
          target="_blank"
          rel="noopener noreferrer"
          className="text-xs md:text-sm text-wgt-muted hover:text-wgt-fog underline underline-offset-2"
        >
          {secondaryLabel}
        </a>
      </div>
    </div>
  );
}
