import { useCallback, useEffect, useState } from 'react';

import {
  addFavorite,
  getFavoriteCountForSchedule,
  getFootprintCountForSchedule,
  isFavorite,
  isFootprint,
  loadSchedule,
  removeFavorite,
  toggleFootprint,
} from './dataUtils';

/**
 * Reactive favorites state synced via favoritesChanged / storage events.
 */
export function useFavorites() {
  const [tick, setTick] = useState(0);

  useEffect(() => {
    const refresh = () => setTick((n) => n + 1);
    window.addEventListener('favoritesChanged', refresh);
    const handleStorage = (event: StorageEvent) => {
      if (event.key === 'wgt-favorites' || event.key === 'wgt-schedule') refresh();
    };
    window.addEventListener('storage', handleStorage);
    window.addEventListener('scheduleChanged', refresh);
    return () => {
      window.removeEventListener('favoritesChanged', refresh);
      window.removeEventListener('storage', handleStorage);
      window.removeEventListener('scheduleChanged', refresh);
    };
  }, []);

  const schedule = loadSchedule();
  const count = getFavoriteCountForSchedule(schedule);

  const checkFavorite = useCallback(
    (eventId: string) => {
      void tick;
      return isFavorite(eventId);
    },
    [tick]
  );

  const toggleFavorite = useCallback((eventId: string) => {
    if (isFavorite(eventId)) {
      removeFavorite(eventId);
    } else {
      addFavorite(eventId);
    }
  }, []);

  const checkFootprint = useCallback(
    (eventId: string) => {
      void tick;
      return isFootprint(eventId);
    },
    [tick],
  );

  const togglePlanned = useCallback((eventId: string) => {
    toggleFootprint(eventId);
  }, []);

  const plannedCount = getFootprintCountForSchedule(schedule);

  return {
    count,
    plannedCount,
    isFavorite: checkFavorite,
    toggleFavorite,
    isFootprint: checkFootprint,
    toggleFootprint: togglePlanned,
  };
}
