import type { NavigateFunction } from 'react-router';

import { markExplicitAppHistoryBack } from './uaVisualTransition';
import { prepareHistoryBackNavigation } from './navDirection';

export const navTransition = { viewTransition: true } as const;

export function navigateBack(navigate: NavigateFunction): void {
  markExplicitAppHistoryBack();
  prepareHistoryBackNavigation();
  void navigate(-1);
}
