/**
 * Data models for the WGT web app
 */

/**
 * Represents a band or artist performing at the festival
 */
export interface Band {
  id: string;
  name: string;
  description?: string;
  genre?: string;
  imageUrl?: string;
  country?: string; // Country code for music bands (e.g., "D", "UK", "US")
}

/**
 * Represents a venue or location where performances take place
 */
export interface Location {
  id: string;
  name: string;
  address?: string;
  city?: string;
  mapUrl?: string;
  lat?: number;
  lng?: number;
}

/**
 * Represents a performance event by a band at a specific location and time
 */
export interface Event {
  id: string;
  bandId: string;
  locationId: string;
  date: string; // ISO date string
  startTime: string; // 24-hour format (HH:MM)
  endTime?: string; // 24-hour format (HH:MM)
  category: 'band' | 'show' | 'other'; // Category: band (with country flag), show (performance without flag), other (non-performance)
}

/**
 * Extended event with band and location information
 */
export interface EventWithDetails extends Event {
  band: Band;
  location: Location;
}

/**
 * User's favorite events and planned picks (footprints).
 * Footprints must be a subset of starred favorites.
 */
export interface Favorites {
  events: string[];
  footprints: string[];
}

/**
 * Schedule data structure
 */
export interface Schedule {
  bands: Band[];
  locations: Location[];
  events: Event[];
}

/** Date / venue / category filters (shown in Filter Events UI). Nav search uses `EventListFilters.searchTerm`. */
export interface FacetFilterOptions {
  date: string;
  locationId: string;
  category: string;
  myPicksOnly: boolean;
}

export const EMPTY_FACET_FILTERS: FacetFilterOptions = {
  date: '',
  locationId: '',
  category: '',
  myPicksOnly: false,
};

/** Facets plus global nav search query when filtering event lists */
export interface EventListFilters extends FacetFilterOptions {
  searchTerm: string;
}