import { EventWithDetails } from '../models/types';

const DEFAULT_DURATION_MINUTES = 60;

/** Overlap at or below this (minutes) is a tight window, not a hard clash. */
export const TIGHT_OVERLAP_MAX_MINUTES = 20;

export type PickConflictLevel = 'squeeze' | 'clash';

/** Minutes from midnight for HH:MM on the festival day. */
export function parseTimeToMinutes(time: string): number {
  const [hours, minutes] = time.split(':').map(Number);
  return hours * 60 + minutes;
}

export function getEventEndMinutes(event: EventWithDetails): number {
  if (event.endTime) {
    return parseTimeToMinutes(event.endTime);
  }
  return parseTimeToMinutes(event.startTime) + DEFAULT_DURATION_MINUTES;
}

export function formatMinutesAsTime(totalMinutes: number): string {
  const hours = Math.floor(totalMinutes / 60) % 24;
  const minutes = totalMinutes % 60;
  return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;
}

function overlapMinutes(
  aStart: number,
  aEnd: number,
  bStart: number,
  bEnd: number,
): number {
  return Math.max(0, Math.min(aEnd, bEnd) - Math.max(aStart, bStart));
}

function levelForOverlapMinutes(minutes: number): PickConflictLevel {
  return minutes <= TIGHT_OVERLAP_MAX_MINUTES ? 'squeeze' : 'clash';
}

function worseConflictLevel(
  current: PickConflictLevel | undefined,
  next: PickConflictLevel,
): PickConflictLevel {
  if (current === 'clash' || next === 'clash') return 'clash';
  return 'squeeze';
}

/**
 * Per-event conflict level when picks overlap (1h assumed if no endTime).
 * Small overlaps (e.g. from guessed set length) are "squeeze"; larger ones are "clash".
 */
export function getPickConflictLevels(events: EventWithDetails[]): Map<string, PickConflictLevel> {
  const sorted = [...events].sort((a, b) => a.startTime.localeCompare(b.startTime));
  const levels = new Map<string, PickConflictLevel>();

  for (let i = 0; i < sorted.length; i++) {
    const a = sorted[i];
    const aStart = parseTimeToMinutes(a.startTime);
    const aEnd = getEventEndMinutes(a);

    for (let j = i + 1; j < sorted.length; j++) {
      const b = sorted[j];
      const bStart = parseTimeToMinutes(b.startTime);
      if (bStart >= aEnd) break;

      const bEnd = getEventEndMinutes(b);
      const overlap = overlapMinutes(aStart, aEnd, bStart, bEnd);
      if (overlap <= 0) continue;

      const level = levelForOverlapMinutes(overlap);
      levels.set(a.id, worseConflictLevel(levels.get(a.id), level));
      levels.set(b.id, worseConflictLevel(levels.get(b.id), level));
    }
  }

  return levels;
}

/** Event IDs that overlap another pick on the same day. */
export function findOverlappingEventIds(events: EventWithDetails[]): Set<string> {
  return new Set(getPickConflictLevels(events).keys());
}

/** Count tight windows / clashes between consecutive picks (n picks → up to n−1 pairs). */
export function countPickConflictPairs(events: EventWithDetails[]): {
  clash: number;
  squeeze: number;
} {
  const sorted = [...events].sort((a, b) => a.startTime.localeCompare(b.startTime));
  let clash = 0;
  let squeeze = 0;

  for (let i = 0; i < sorted.length - 1; i++) {
    const a = sorted[i];
    const b = sorted[i + 1];
    const overlap = overlapMinutes(
      parseTimeToMinutes(a.startTime),
      getEventEndMinutes(a),
      parseTimeToMinutes(b.startTime),
      getEventEndMinutes(b),
    );
    if (overlap <= 0) continue;

    if (levelForOverlapMinutes(overlap) === 'clash') clash++;
    else squeeze++;
  }

  return { clash, squeeze };
}

export function formatDayConflictWarning(events: EventWithDetails[]): string | undefined {
  const { clash: clashCount, squeeze: squeezeCount } = countPickConflictPairs(events);

  const parts: string[] = [];
  if (clashCount > 0) {
    parts.push(`${clashCount} clash${clashCount !== 1 ? 'es' : ''}`);
  }
  if (squeezeCount > 0) {
    parts.push(`${squeezeCount} squeeze${squeezeCount !== 1 ? 'es' : ''}`);
  }
  return parts.length > 0 ? parts.join(' · ') : undefined;
}

export function getDaySummary(events: EventWithDetails[]): string {
  if (events.length === 0) return '';

  const venueCount = new Set(events.map((e) => e.locationId)).size;
  const sorted = [...events].sort((a, b) => a.startTime.localeCompare(b.startTime));
  const first = sorted[0].startTime;
  let lastEnd = getEventEndMinutes(sorted[0]);

  for (const event of sorted) {
    lastEnd = Math.max(lastEnd, getEventEndMinutes(event));
  }

  const last = formatMinutesAsTime(lastEnd);
  const showLabel = events.length === 1 ? 'show' : 'shows';
  const venueLabel = venueCount === 1 ? 'venue' : 'venues';

  return `${events.length} ${showLabel} · ${venueCount} ${venueLabel} · ${first}–${last}`;
}

/** Gap label between two consecutive events (minutes). */
export function formatGapMinutes(gapMinutes: number): string | null {
  if (gapMinutes <= 0) return null;
  if (gapMinutes < 60) return `${gapMinutes} min free`;
  const hours = Math.floor(gapMinutes / 60);
  const mins = gapMinutes % 60;
  if (mins === 0) return `${hours}h free`;
  return `${hours}h ${mins}m free`;
}

export function getGapBeforeEvent(
  events: EventWithDetails[],
  index: number
): string | null {
  if (index <= 0) return null;
  const prev = events[index - 1];
  const current = events[index];
  const gap = parseTimeToMinutes(current.startTime) - getEventEndMinutes(prev);
  return formatGapMinutes(gap);
}

/** Parse YYYY-MM-DD as local calendar parts (avoids UTC midnight shifts). */
export function parseLocalDateParts(dateStr: string): {
  year: number;
  month: number;
  day: number;
} {
  const [year, month, day] = dateStr.split('T')[0].split('-').map(Number);
  return { year, month, day };
}

export function isSameCalendarDay(dateStr: string, reference: Date = new Date()): boolean {
  const { year, month, day } = parseLocalDateParts(dateStr);
  return (
    year === reference.getFullYear() &&
    month === reference.getMonth() + 1 &&
    day === reference.getDate()
  );
}

export function formatPicksDayLabel(dateStr: string): string {
  const { year, month, day } = parseLocalDateParts(dateStr);
  return new Date(year, month - 1, day).toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
  });
}

/** Grace period after start before an event is treated as passed (matches Upcoming Events). */
export const UPCOMING_EVENT_GRACE_MS = 60 * 60 * 1000;

export function isEventUpcoming(
  event: EventWithDetails,
  reference: Date = new Date(),
): boolean {
  const startOfToday = new Date(
    reference.getFullYear(),
    reference.getMonth(),
    reference.getDate(),
  );
  const eventStart = new Date(`${event.date} ${event.startTime}`);
  return (
    eventStart >= startOfToday &&
    eventStart.getTime() + UPCOMING_EVENT_GRACE_MS >= reference.getTime()
  );
}

export type HomePicksSection = {
  /** Upcoming picks shown in the Home timeline (capped). */
  events: EventWithDetails[];
  /** All favorites on the focus day (for day summary; may include passed picks). */
  allDayEvents: EventWithDetails[];
  focusDate: string;
  isToday: boolean;
};

function buildHomePicksForDay(
  dayEvents: EventWithDetails[],
  maxCount: number,
  reference: Date,
  isToday: boolean,
): HomePicksSection {
  const upcoming = dayEvents.filter((event) => isEventUpcoming(event, reference));
  return {
    events: upcoming.slice(0, maxCount),
    allDayEvents: dayEvents,
    focusDate: dayEvents[0].date,
    isToday,
  };
}

/**
 * Picks for the Home section: today's favorites, or the next festival day with picks.
 */
export function getHomePicksSection(
  favorites: EventWithDetails[],
  maxCount = 5,
  reference: Date = new Date(),
): HomePicksSection | null {
  if (favorites.length === 0) return null;

  const sorted = [...favorites].sort((a, b) => {
    const da = parseLocalDateParts(a.date);
    const db = parseLocalDateParts(b.date);
    const byDate =
      da.year - db.year || da.month - db.month || da.day - db.day;
    if (byDate !== 0) return byDate;
    return a.startTime.localeCompare(b.startTime);
  });

  const ref = {
    year: reference.getFullYear(),
    month: reference.getMonth() + 1,
    day: reference.getDate(),
  };
  const compareToRef = (dateStr: string) => {
    const d = parseLocalDateParts(dateStr);
    return d.year - ref.year || d.month - ref.month || d.day - ref.day;
  };

  const todayEvents = sorted.filter((event) => isSameCalendarDay(event.date, reference));
  if (todayEvents.length > 0) {
    return buildHomePicksForDay(todayEvents, maxCount, reference, true);
  }

  const upcoming = sorted.filter((event) => compareToRef(event.date) >= 0);
  if (upcoming.length === 0) return null;

  const focusDate = upcoming[0].date;
  const dayEvents = upcoming.filter((event) => event.date === focusDate);

  return buildHomePicksForDay(
    dayEvents,
    maxCount,
    reference,
    isSameCalendarDay(focusDate, reference),
  );
}
