import { prefersReducedMotion } from './platform';

/** Saved scroll positions need post-transition layout before restore can succeed. */
export function shouldDeferScrollRestore(restoreTop: number | null): boolean {
  return restoreTop !== null && restoreTop > 0;
}

/** Revisit any tab with a saved scroll position — direction is irrelevant. */
export function shouldSmoothScrollRestore(restoreTop: number | null): boolean {
  return shouldDeferScrollRestore(restoreTop) && !prefersReducedMotion();
}
