import type { Router } from 'react-router';

import {
  appPathFromUrl,
  applyPendingViewTransitionClass,
  clearNavDirectionMarkers,
  currentAppPath,
  getPendingNavDirection,
  type NavDirection,
  readRestoreScrollTop,
  resolveNavDirection,
  resolveTraverseDirection,
  stampBackNavigation,
  stampForwardNavigation,
} from './navDirection';
import {
  applyPageScrollRestore,
  getPageScrollElement,
  savePageScrollForPath,
  scrollPageToTop,
} from './pageScroll';
import { hasWebKitScrollRestoreQuirk, isIosSafariFamily, setScrollRestoration } from './platform';
import {
  consumeExplicitAppHistoryBack,
  consumeUAVisualTransition,
} from './uaVisualTransition';
import {
  shouldDeferScrollRestore,
  shouldSmoothScrollRestore,
} from './scrollRestorePolicy';

function isHistoryForward(event: NavigateEvent, nav: Navigation): boolean {
  if (event.navigationType !== 'traverse') return false;
  const currentIndex = nav.currentEntry?.index;
  const destIndex = event.destination.index;
  return currentIndex != null && destIndex >= 0 && destIndex > currentIndex;
}

let directionInstalled = false;
let patchInstalled = false;
let lastPath = '/';
let explicitForwardTraverse = false;

function applyNavDirection(
  fromPath: string,
  destPath: string,
  direction: NavDirection,
): void {
  if (direction === 'back') {
    stampBackNavigation(fromPath, destPath);
  } else {
    savePageScrollForPath(fromPath);
    stampForwardNavigation(destPath);
  }
}

export function installNavigationDirection(router: Router): void {
  if (directionInstalled || typeof window === 'undefined') return;
  directionInstalled = true;
  lastPath = currentAppPath();

  const nav = (window as Window & { navigation?: Navigation }).navigation;

  function handleNavigate(event: NavigateEvent): void {
    if (event.hashChange) return;

    const fromPath = currentAppPath();
    const destPath = appPathFromUrl(event.destination.url);

    if (event.navigationType === 'traverse') {
      const historyForward = !!(nav && isHistoryForward(event, nav));
      const direction = resolveTraverseDirection(fromPath, destPath, historyForward);
      explicitForwardTraverse = direction === 'forward';
      applyNavDirection(fromPath, destPath, direction);
    } else {
      explicitForwardTraverse = false;
      applyNavDirection(fromPath, destPath, resolveNavDirection(fromPath, destPath));
    }

    lastPath = destPath;
  }

  function handlePopState(): void {
    const destPath = currentAppPath();
    if (!nav) {
      applyNavDirection(lastPath, destPath, resolveTraverseDirection(lastPath, destPath, false));
    }
    lastPath = destPath;
  }

  if (nav) {
    nav.addEventListener('navigate', handleNavigate);
  }

  window.addEventListener('popstate', handlePopState, { capture: true });

  if (!nav) {
    const originalPushState = history.pushState.bind(history);
    history.pushState = (...args) => {
      const fromPath = lastPath;
      originalPushState(...args);
      const destPath = currentAppPath();
      explicitForwardTraverse = false;
      applyNavDirection(fromPath, destPath, resolveNavDirection(fromPath, destPath));
      lastPath = destPath;
    };
  }

  router.subscribe((state, { viewTransitionOpts }) => {
    if (
      viewTransitionOpts &&
      state.historyAction === 'POP' &&
      !explicitForwardTraverse &&
      getPendingNavDirection() !== 'back'
    ) {
      const destPath = currentAppPath();
      applyNavDirection(
        lastPath,
        destPath,
        resolveTraverseDirection(lastPath, destPath, false),
      );
    }
    explicitForwardTraverse = false;
  });
}

function immediateViewTransition(
  updateCallback: () => void | Promise<void>,
  onDone: () => void,
): ViewTransition {
  const finished = (async () => {
    const result = updateCallback();
    if (result instanceof Promise) await result;
    onDone();
  })();

  return {
    finished,
    ready: finished,
    updateCallbackDone: finished,
    skipTransition: () => {},
  } as ViewTransition;
}

export function installViewTransitionPatch(): void {
  if (patchInstalled || typeof window === 'undefined') return;

  setScrollRestoration('manual');

  const startVT = document.startViewTransition?.bind(document);
  if (!startVT) return;

  patchInstalled = true;

  document.startViewTransition = (updateCallback) => {
    const restoreTop = readRestoreScrollTop();
    const webKitScroll = hasWebKitScrollRestoreQuirk();
    const skipForUaVisualTransition =
      consumeUAVisualTransition() && !consumeExplicitAppHistoryBack();
    const smoothRestore = shouldSmoothScrollRestore(restoreTop);
    const deferRestore = shouldDeferScrollRestore(restoreTop);
    const safariBackNav =
      isIosSafariFamily() && getPendingNavDirection() === 'back';

    const finishScrollRestoration = () => {
      if (safariBackNav) {
        setScrollRestoration('manual');
      }
    };

    if (safariBackNav) {
      setScrollRestoration('auto');
    }

    if (skipForUaVisualTransition) {
      return immediateViewTransition(updateCallback, () => {
        applyPageScrollRestore(restoreTop, true, smoothRestore);
        clearNavDirectionMarkers();
        finishScrollRestoration();
      });
    }

    const direction = applyPendingViewTransitionClass();
    getPageScrollElement()?.classList.add('vt-scroll-lock');

    const update = () => {
      const result = updateCallback();
      if (deferRestore) {
        // Drop the source page scroll so restore animates from top, not mid-page.
        scrollPageToTop();
      } else if (!webKitScroll) {
        if (result instanceof Promise) {
          return result.then(() => applyPageScrollRestore(restoreTop, false, smoothRestore));
        }
        applyPageScrollRestore(restoreTop, false, smoothRestore);
      }
      return result;
    };

    let transition: ViewTransition;
    try {
      transition = startVT({ update, types: [direction] });
    } catch {
      transition = startVT(update);
    }

    void transition.finished.finally(() => {
      clearNavDirectionMarkers();
      getPageScrollElement()?.classList.remove('vt-scroll-lock');
      applyPageScrollRestore(
        restoreTop,
        webKitScroll || deferRestore,
        smoothRestore,
      );
      finishScrollRestoration();
    });

    return transition;
  };
}
