import { Location, Schedule } from '../models/types';

export interface VenueDetails {
  address?: string;
  lat?: number;
  lng?: number;
  mapUrl?: string;
}

export type VenueCatalog = Record<string, VenueDetails>;

/** Sub-venues that share coordinates with a parent entry in venues.json */
const VENUE_ALIASES: Record<string, string> = {
  'agra-Halle 4.2': 'agra',
  'Mittelaltermarkt - Moritzbastei': 'Moritzbastei',
  'Volkspalast Kantine': 'Volkspalast',
  'Volkspalast Kuppelhalle': 'Volkspalast',
  'Parkschloß - Barocksaal': 'Parkschloß',
  'Parkschloß - Ballsaal': 'Parkschloß',
};

function resolveCatalogKey(name: string): string {
  return VENUE_ALIASES[name] ?? name;
}

export function enrichLocation(location: Location, catalog: VenueCatalog): Location {
  const catalogKey = resolveCatalogKey(location.name);
  const details = catalog[catalogKey];
  if (!details) {
    return location;
  }

  return {
    ...location,
    address: location.address ?? details.address,
    lat: location.lat ?? details.lat,
    lng: location.lng ?? details.lng,
    mapUrl: location.mapUrl ?? details.mapUrl,
  };
}

export function enrichScheduleLocations(schedule: Schedule, catalog: VenueCatalog): Schedule {
  if (Object.keys(catalog).length === 0) {
    return schedule;
  }

  return {
    ...schedule,
    locations: schedule.locations.map((location) => enrichLocation(location, catalog)),
  };
}
