import React, { createContext, useContext, useEffect, useState, type ReactNode } from 'react';

export interface NavigationSearchContextValue {
  query: string;
  setQuery: (value: string) => void;
  panelOpen: boolean;
  togglePanel: () => void;
  closePanel: () => void;
}

const NavigationSearchContext = createContext<NavigationSearchContextValue | null>(null);

export function NavigationSearchProvider({ children }: { children: ReactNode }) {
  const [query, setQuery] = useState('');
  const [panelOpen, setPanelOpen] = useState(false);

  const closePanel = () => setPanelOpen(false);
  const togglePanel = () => setPanelOpen((open) => !open);

  useEffect(() => {
    if (!panelOpen) return;
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        closePanel();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [panelOpen]);

  const value: NavigationSearchContextValue = {
    query,
    setQuery,
    panelOpen,
    closePanel,
    togglePanel,
  };

  return (
    <NavigationSearchContext.Provider value={value}>{children}</NavigationSearchContext.Provider>
  );
}

export function useNavigationSearch(): NavigationSearchContextValue {
  const ctx = useContext(NavigationSearchContext);
  if (!ctx) {
    throw new Error('useNavigationSearch must be used within NavigationSearchProvider');
  }
  return ctx;
}
