import React from 'react';

import { Location } from '../models/types';
import {
  buildAppleMapsSearchUrl,
  buildGoogleMapsSearchUrl,
} from '../utils/mapUtils';

interface VenueMapsLinkProps {
  location: Location;
}

export function VenueMapsLink({ location }: VenueMapsLinkProps) {
  const googleUrl = buildGoogleMapsSearchUrl(location);
  const appleUrl = buildAppleMapsSearchUrl(location);

  const handleClick = (event: React.MouseEvent) => {
    event.stopPropagation();
  };

  return (
    <span className="inline-flex items-center gap-2 ml-1 shrink-0" onClick={handleClick}>
      <a
        href={googleUrl}
        target="_blank"
        rel="noopener noreferrer"
        className="text-wgt-muted hover:text-wgt-fog underline underline-offset-2 text-xs md:text-sm"
        aria-label={`Open ${location.name} in Google Maps`}
        title="Open in Google Maps"
      >
        Maps
      </a>
      <span className="text-wgt-muted/40" aria-hidden="true">·</span>
      <a
        href={appleUrl}
        target="_blank"
        rel="noopener noreferrer"
        className="text-wgt-muted hover:text-wgt-fog underline underline-offset-2 text-xs md:text-sm"
        aria-label={`Open ${location.name} in Apple Maps`}
        title="Open in Apple Maps"
      >
        Apple
      </a>
    </span>
  );
}
