import React, { useEffect, useState } from 'react';

interface FootprintButtonProps {
  active: boolean;
  disabled?: boolean;
  onClick: (e: React.MouseEvent) => void;
  size?: 'sm' | 'md';
  className?: string;
  animateOnToggle?: boolean;
}

export function FootprintButton({
  active,
  disabled = false,
  onClick,
  size = 'md',
  className = '',
  animateOnToggle = false,
}: FootprintButtonProps) {
  const [pop, setPop] = useState(false);

  useEffect(() => {
    if (!pop) return;
    const timer = window.setTimeout(() => setPop(false), 320);
    return () => window.clearTimeout(timer);
  }, [pop]);

  const handleClick = (e: React.MouseEvent) => {
    if (disabled) return;
    onClick(e);
    if (animateOnToggle) setPop(true);
  };

  const iconClass = size === 'sm' ? 'w-5 h-5' : 'w-6 h-6 md:w-7 md:h-7';
  const hitArea = size === 'sm' ? 'p-1.5 -m-1.5' : 'p-2 -m-2 min-w-11 min-h-11';

  return (
    <button
      type="button"
      onClick={handleClick}
      disabled={disabled}
      className={`footprint-icon shrink-0 inline-flex items-center justify-center ${hitArea} ${active ? 'active' : ''} ${disabled ? 'footprint-icon--disabled' : ''} ${pop ? 'footprint-icon--pop' : ''} ${className}`.trim()}
      aria-label={active ? 'Remove from planned picks' : 'Mark as going'}
      aria-pressed={active}
    >
      <svg
        className={iconClass}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={active ? 0 : 1.6}
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <ellipse
          cx="8.25"
          cy="15.25"
          rx="2.75"
          ry="4.25"
          transform="rotate(-32 8.25 15.25)"
          fill={active ? 'currentColor' : 'none'}
        />
        <ellipse
          cx="14.75"
          cy="8.75"
          rx="2.75"
          ry="4.25"
          transform="rotate(-32 14.75 8.75)"
          fill={active ? 'currentColor' : 'none'}
        />
      </svg>
    </button>
  );
}
