import {
  getPageScrollElement,
  restoreScrollTopForPath,
  savePageScrollForPath,
} from './pageScroll';

export type NavDirection = 'back' | 'forward';

export const NAV_RESTORE_SCROLL_ATTR = 'data-nav-restore-scroll';

export { resolveNavDirection, resolveTraverseDirection } from './mainTabNav';

/** Scroll target stamped before a navigation commits (see view transition patch). */
export function readRestoreScrollTop(): number | null {
  const raw = document.documentElement.getAttribute(NAV_RESTORE_SCROLL_ATTR);
  if (raw === null) return null;
  const top = Number(raw);
  return Number.isFinite(top) ? top : 0;
}

let pendingNavDirection: NavDirection = 'forward';

export function getPendingNavDirection(): NavDirection {
  return pendingNavDirection;
}

export function currentAppPath(): string {
  const base = import.meta.env.BASE_URL.replace(/\/$/, '') || '';
  const path = window.location.pathname;
  if (base && path.startsWith(base)) {
    return path.slice(base.length) || '/';
  }
  return path;
}

export function appPathFromUrl(url: string): string {
  const base = import.meta.env.BASE_URL.replace(/\/$/, '') || '';
  let path = new URL(url, window.location.origin).pathname;
  if (base && path.startsWith(base)) {
    path = path.slice(base.length) || '/';
  }
  return path;
}

function applyViewTransitionClass(direction: NavDirection): void {
  getPageScrollElement()?.style.setProperty('view-transition-class', direction);
}

function clearViewTransitionClass(): void {
  getPageScrollElement()?.style.removeProperty('view-transition-class');
}

function setRestoreScrollAttribute(destPath?: string, fallbackTop?: number): void {
  const savedTop = restoreScrollTopForPath(destPath);
  if (savedTop !== null) {
    document.documentElement.setAttribute(NAV_RESTORE_SCROLL_ATTR, String(savedTop));
  } else if (fallbackTop !== undefined) {
    document.documentElement.setAttribute(NAV_RESTORE_SCROLL_ATTR, String(fallbackTop));
  } else {
    document.documentElement.removeAttribute(NAV_RESTORE_SCROLL_ATTR);
  }
}

export function stampForwardNavigation(destPath?: string): void {
  pendingNavDirection = 'forward';
  applyViewTransitionClass('forward');
  setRestoreScrollAttribute(destPath);
}

export function stampBackNavigation(fromPath: string, destPath: string): void {
  pendingNavDirection = 'back';
  savePageScrollForPath(fromPath);
  applyViewTransitionClass('back');
  setRestoreScrollAttribute(destPath, 0);
}

export function prepareHistoryBackNavigation(): void {
  const fromPath = currentAppPath();
  const nav = (window as Window & { navigation?: Navigation }).navigation;
  const priorIndex = (nav?.currentEntry?.index ?? 0) - 1;
  const priorEntry =
    nav?.entries && priorIndex >= 0 ? nav.entries()[priorIndex] : undefined;

  if (priorEntry) {
    stampBackNavigation(fromPath, appPathFromUrl(priorEntry.url));
    return;
  }

  pendingNavDirection = 'back';
  savePageScrollForPath(fromPath);
  applyViewTransitionClass('back');
  setRestoreScrollAttribute(undefined, 0);
}

export function applyPendingViewTransitionClass(): NavDirection {
  applyViewTransitionClass(pendingNavDirection);
  return pendingNavDirection;
}

export function clearNavDirectionMarkers(): void {
  pendingNavDirection = 'forward';
  document.documentElement.removeAttribute(NAV_RESTORE_SCROLL_ATTR);
  clearViewTransitionClass();
}
