/** Safari/WebKit: `hasUAVisualTransition` on popstate / NavigateEvent — skip custom VT when set. */

type UAVisualTransitionEvent = {
  hasUAVisualTransition?: boolean;
};

let uaDetectionInstalled = false;
let pendingUAVisualTransition = false;
let explicitAppHistoryBack = false;

function readUAVisualTransition(event: Event): boolean {
  const flag = (event as UAVisualTransitionEvent).hasUAVisualTransition;
  return typeof flag === 'boolean' ? flag : false;
}

/** Sticky: a later navigate without the flag must not clear a popstate that set it. */
function captureUAVisualTransition(event: Event): void {
  if (readUAVisualTransition(event)) {
    pendingUAVisualTransition = true;
  }
}

function resetUAVisualTransition(): void {
  pendingUAVisualTransition = false;
}

export function markExplicitAppHistoryBack(): void {
  explicitAppHistoryBack = true;
}

export function consumeExplicitAppHistoryBack(): boolean {
  const value = explicitAppHistoryBack;
  explicitAppHistoryBack = false;
  return value;
}

export function consumeUAVisualTransition(): boolean {
  const value = pendingUAVisualTransition;
  pendingUAVisualTransition = false;
  return value;
}

export function installUAVisualTransitionDetection(): void {
  if (uaDetectionInstalled || typeof window === 'undefined') return;
  uaDetectionInstalled = true;

  window.addEventListener('popstate', captureUAVisualTransition, { capture: true });

  const nav = (window as Window & { navigation?: Navigation }).navigation;
  if (nav) {
    nav.addEventListener('navigate', (event: NavigateEvent) => {
      if (event.hashChange) return;
      if (event.navigationType === 'traverse') {
        captureUAVisualTransition(event);
      } else {
        resetUAVisualTransition();
      }
    });
  }
}
