/**
 * Utility functions for managing day group collapsed state persistence
 */

const DAY_GROUP_STATE_KEY = 'wgt-day-group-states';

interface DayGroupStates {
  [pageUrl: string]: {
    [date: string]: boolean | number;
    timestamp: number;
  };
}

/**
 * Get all stored day group states
 */
function getStoredDayGroupStates(): DayGroupStates {
  try {
    const stored = localStorage.getItem(DAY_GROUP_STATE_KEY);
    return stored ? JSON.parse(stored) : {};
  } catch (error) {
    console.warn('Failed to load day group states:', error);
    return {};
  }
}

/**
 * Save day group states to localStorage
 */
function saveStoredDayGroupStates(states: DayGroupStates): void {
  try {
    localStorage.setItem(DAY_GROUP_STATE_KEY, JSON.stringify(states));
  } catch (error) {
    console.warn('Failed to save day group states:', error);
  }
}

/**
 * Get the current page URL for day group state tracking
 */
function getCurrentPageUrl(): string {
  return window.location.pathname;
}

/**
 * Load day group collapsed states for the current page
 */
export function loadDayGroupStates(): Record<string, boolean> {
  const allStates = getStoredDayGroupStates();
  const currentUrl = getCurrentPageUrl();
  const pageStates = allStates[currentUrl];
  
  if (pageStates) {
    // Clean up old states (older than 24 hours)
    const oneDayAgo = Date.now() - (24 * 60 * 60 * 1000);
    if (pageStates.timestamp < oneDayAgo) {
      delete allStates[currentUrl];
      saveStoredDayGroupStates(allStates);
      return {};
    }
    
    // Return states without timestamp, filtering to only boolean values
    const { timestamp, ...allProperties } = pageStates;
    const states: Record<string, boolean> = {};
    Object.entries(allProperties).forEach(([key, value]) => {
      if (typeof value === 'boolean') {
        states[key] = value;
      }
    });
    return states;
  }
  
  return {};
}

/**
 * Save day group collapsed states for the current page
 */
export function saveDayGroupStates(expandedDays: Record<string, boolean>): void {
  const allStates = getStoredDayGroupStates();
  const currentUrl = getCurrentPageUrl();
  
  allStates[currentUrl] = {
    ...expandedDays,
    timestamp: Date.now()
  };
  
  saveStoredDayGroupStates(allStates);
}

/**
 * Clear day group states for the current page
 */
export function clearDayGroupStates(): void {
  const allStates = getStoredDayGroupStates();
  const currentUrl = getCurrentPageUrl();
  delete allStates[currentUrl];
  saveStoredDayGroupStates(allStates);
}

/**
 * Clear all stored day group states
 */
export function clearAllDayGroupStates(): void {
  try {
    localStorage.removeItem(DAY_GROUP_STATE_KEY);
  } catch (error) {
    console.warn('Failed to clear day group states:', error);
  }
}

/**
 * Check if a day should be expanded (defaults to true if not set)
 */
export function isDayExpanded(date: string, expandedDays: Record<string, boolean>): boolean {
  return expandedDays[date] !== false; // Default to expanded
}

/**
 * Toggle day expanded state
 */
export function toggleDayExpanded(date: string, expandedDays: Record<string, boolean>): Record<string, boolean> {
  const newExpandedDays = {
    ...expandedDays,
    [date]: expandedDays[date] === undefined ? false : !expandedDays[date]
  };
  
  // Save to localStorage
  saveDayGroupStates(newExpandedDays);
  
  return newExpandedDays;
} 