import React, { useState, useEffect } from 'react';

import type { FacetFilterOptions } from '../models/types';
import { EMPTY_FACET_FILTERS } from '../models/types';

interface EventFilterProps {
  onFilterChange: (filters: FacetFilterOptions) => void;
  locations: { id: string; name: string }[];
  dates: string[];
  initialFilters?: FacetFilterOptions | null;
  showMyPicksToggle?: boolean;
}

export function EventFilter({
  onFilterChange,
  locations,
  dates,
  initialFilters,
  showMyPicksToggle = false,
}: EventFilterProps) {
  const [filters, setFilters] = useState<FacetFilterOptions>(
    () => initialFilters ?? EMPTY_FACET_FILTERS,
  );
  const [isExpanded, setIsExpanded] = useState(false);

  useEffect(() => {
    if (initialFilters) {
      setFilters(initialFilters);
    }
  }, [initialFilters]);

  const handleFilterChange = (key: keyof FacetFilterOptions, value: string | boolean) => {
    const newFilters = { ...filters, [key]: value };
    setFilters(newFilters);
    onFilterChange(newFilters);
  };

  const formatDate = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
    });
  };

  const toggleExpanded = () => {
    setIsExpanded(!isExpanded);
  };

  const hasActiveFacets =
    filters.date || filters.locationId || filters.category || filters.myPicksOnly;

  return (
    <div className="bg-gray-800 rounded-lg mb-2 overflow-hidden">
      <div
        className="p-4 cursor-pointer flex items-center justify-between hover:bg-gray-700 transition-colors md:cursor-default md:hover:bg-gray-800"
        onClick={toggleExpanded}
      >
        <div className="flex flex-wrap items-center gap-3">
          <h2 className="text-xl font-semibold">Filter Events</h2>
          {hasActiveFacets && (
            <span className="px-2 py-1 bg-wgt-red text-white text-xs rounded-full">Active</span>
          )}
          {showMyPicksToggle && (
            <label
              className={`filter-picks-toggle ${filters.myPicksOnly ? 'filter-picks-toggle--on' : ''}`}
              onClick={(e) => e.stopPropagation()}
            >
              <input
                type="checkbox"
                checked={filters.myPicksOnly}
                onChange={(e) => handleFilterChange('myPicksOnly', e.target.checked)}
                className="sr-only"
              />
              <span className="filter-picks-toggle__track" aria-hidden="true">
                <span className="filter-picks-toggle__thumb" />
              </span>
              <span className="filter-picks-toggle__label">Picks only</span>
            </label>
          )}
        </div>
        <div className="ml-4 md:hidden">
          <svg
            className={`w-6 h-6 transform transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        </div>
      </div>

      <div className={`px-4 pb-4 md:block ${isExpanded ? 'block' : 'hidden'}`}>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
            <label className="block text-gray-400 mb-1" htmlFor="date-filter">
              Date
            </label>
            <select
              id="date-filter"
              className="w-full bg-gray-700 text-white rounded p-2 border border-gray-600"
              value={filters.date}
              onChange={(e) => handleFilterChange('date', e.target.value)}
            >
              <option value="">All Dates</option>
              {dates.map((date) => (
                <option key={date} value={date}>
                  {formatDate(date)}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-gray-400 mb-1" htmlFor="location-filter">
              Venue
            </label>
            <select
              id="location-filter"
              className="w-full bg-gray-700 text-white rounded p-2 border border-gray-600"
              value={filters.locationId}
              onChange={(e) => handleFilterChange('locationId', e.target.value)}
            >
              <option value="">All Venues</option>
              {locations.map((location) => (
                <option key={location.id} value={location.id}>
                  {location.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-gray-400 mb-1" htmlFor="category-filter">
              Category
            </label>
            <select
              id="category-filter"
              className="w-full bg-gray-700 text-white rounded p-2 border border-gray-600"
              value={filters.category}
              onChange={(e) => handleFilterChange('category', e.target.value)}
            >
              <option value="">All Categories</option>
              <option value="band">Bands</option>
              <option value="show">Show Acts</option>
              <option value="other">Other Events</option>
            </select>
          </div>
        </div>
      </div>
    </div>
  );
}
