import type { NavDirection } from './navDirection';

/** Left-to-right tab order in the header (Home → Schedule → Favs). */
const MAIN_TAB_PATHS = ['/', '/schedule', '/favorites'] as const;

function mainTabIndex(path: string): number | null {
  const idx = MAIN_TAB_PATHS.indexOf(path as (typeof MAIN_TAB_PATHS)[number]);
  return idx >= 0 ? idx : null;
}

/** Tab-carousel direction when both paths are main tabs; otherwise `null`. */
export function directionBetweenMainTabs(
  fromPath: string,
  destPath: string,
): NavDirection | null {
  const fromIdx = mainTabIndex(fromPath);
  const destIdx = mainTabIndex(destPath);
  if (fromIdx === null || destIdx === null || fromIdx === destIdx) {
    return null;
  }
  return destIdx > fromIdx ? 'forward' : 'back';
}

/** Link / push navigation — forward unless moving left across main tabs. */
export function resolveNavDirection(
  fromPath: string,
  destPath: string,
): NavDirection {
  return resolveTraverseDirection(fromPath, destPath, true);
}

/** History traverse: tab order when both are main tabs, else browser forward/back. */
export function resolveTraverseDirection(
  fromPath: string,
  destPath: string,
  historyForward: boolean,
): NavDirection {
  return directionBetweenMainTabs(fromPath, destPath) ?? (historyForward ? 'forward' : 'back');
}
