import React from 'react';

interface DayHeaderProps {
  date: string;
  eventCount: number;
  isExpanded: boolean;
  onToggle: (date: string) => void;
  subtitle?: string;
  warning?: string;
}

export function DayHeader({ date, eventCount, isExpanded, onToggle, subtitle, warning }: DayHeaderProps) {
  const formatDateHeader = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  return (
    <div 
      className="day-separator bg-wgt-black/20 p-2 px-4 rounded-lg cursor-pointer hover:bg-wgt-black/30 transition-colors"
      onClick={() => onToggle(date)}
    >
      <div className="flex items-center justify-between gap-3">
        <div className="min-w-0">
          <h2 className="text-xl font-semibold text-wgt-red">
            {formatDateHeader(date)}
          </h2>
          {subtitle && (
            <p className="text-sm text-wgt-muted mt-0.5 truncate">{subtitle}</p>
          )}
          {warning && (
            <p className="text-xs text-wgt-red-glow mt-1 font-medium">{warning}</p>
          )}
        </div>
        <div className="flex items-center shrink-0">
          <span className="text-sm text-gray-400 mr-2">
            {eventCount} event{eventCount !== 1 ? 's' : ''}
          </span>
          <svg 
            className={`w-5 h-5 text-gray-400 transform transition-transform duration-200 ${
              isExpanded ? 'rotate-180' : ''
            }`}
            fill="none" 
            stroke="currentColor" 
            viewBox="0 0 24 24"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        </div>
      </div>
    </div>
  );
} 