import {
  Schedule,
  Event,
  EventWithDetails,
  Favorites,
  Band,
  Location,
  FacetFilterOptions,
  EventListFilters,
  EMPTY_FACET_FILTERS,
} from '../models/types';
import { spreadHashChars, computeMinimalSpreadHashLength } from './spreadHash';

export { spreadHashChars, computeMinimalSpreadHashLength, generateShortHash } from './spreadHash';

const SCHEDULE_FILTER_STORAGE_KEY = 'wgt-schedule-filters';
const SCHEDULE_STORAGE_KEY = 'wgt-schedule';
const FAVORITES_STORAGE_KEY = 'wgt-favorites';

/**
 * Load schedule data from localStorage or return null if not available
 */
export function loadSchedule(): Schedule | null {
  const scheduleData = localStorage.getItem(SCHEDULE_STORAGE_KEY);
  if (scheduleData) {
    try {
      return JSON.parse(scheduleData);
    } catch (error) {
      console.error('Error parsing schedule data:', error);
      return null;
    }
  }
  return null;
}

/**
 * Save schedule data to localStorage
 */
export function saveSchedule(schedule: Schedule): void {
  localStorage.setItem(SCHEDULE_STORAGE_KEY, JSON.stringify(schedule));
  window.dispatchEvent(new CustomEvent('scheduleChanged'));
}

function normalizeFavorites(raw: Partial<Favorites>): Favorites {
  const events = raw.events ?? [];
  const footprints = (raw.footprints ?? []).filter((id) => events.includes(id));
  return { events, footprints };
}

/**
 * Load favorites from localStorage
 */
export function loadFavorites(): Favorites {
  const favoritesData = localStorage.getItem(FAVORITES_STORAGE_KEY);
  if (favoritesData) {
    try {
      return normalizeFavorites(JSON.parse(favoritesData));
    } catch (error) {
      console.error('Error parsing favorites data:', error);
      return { events: [], footprints: [] };
    }
  }
  return { events: [], footprints: [] };
}

/**
 * Save favorites to localStorage
 */
export function saveFavorites(favorites: Favorites): void {
  localStorage.setItem(FAVORITES_STORAGE_KEY, JSON.stringify(normalizeFavorites(favorites)));
}

/**
 * Add an event to favorites
 */
export function addFavorite(eventId: string): void {
  const favorites = loadFavorites();
  if (!favorites.events.includes(eventId)) {
    favorites.events.push(eventId);
    saveFavorites(favorites);
    // Dispatch custom event to notify components of favorites change
    window.dispatchEvent(new CustomEvent('favoritesChanged'));
  }
}

/**
 * Remove an event from favorites
 */
export function removeFavorite(eventId: string): void {
  const favorites = loadFavorites();
  const originalLength = favorites.events.length;
  favorites.events = favorites.events.filter(id => id !== eventId);
  favorites.footprints = favorites.footprints.filter(id => id !== eventId);

  // Only save and dispatch if something was actually removed
  if (favorites.events.length !== originalLength) {
    saveFavorites(favorites);
    // Dispatch custom event to notify components of favorites change
    window.dispatchEvent(new CustomEvent('favoritesChanged'));
  }
}

/**
 * Check if an event is in favorites
 */
export function isFavorite(eventId: string): boolean {
  const favorites = loadFavorites();
  return favorites.events.includes(eventId);
}

/**
 * Check if an event is marked as a planned pick (footprint).
 */
export function isFootprint(eventId: string): boolean {
  const favorites = loadFavorites();
  return favorites.footprints.includes(eventId);
}

/**
 * Mark a favorite event as a planned pick.
 */
export function addFootprint(eventId: string): void {
  const favorites = loadFavorites();
  if (!favorites.events.includes(eventId) || favorites.footprints.includes(eventId)) {
    return;
  }
  favorites.footprints.push(eventId);
  saveFavorites(favorites);
  window.dispatchEvent(new CustomEvent('favoritesChanged'));
}

/**
 * Remove a planned pick mark from an event.
 */
export function removeFootprint(eventId: string): void {
  const favorites = loadFavorites();
  const originalLength = favorites.footprints.length;
  favorites.footprints = favorites.footprints.filter((id) => id !== eventId);
  if (favorites.footprints.length !== originalLength) {
    saveFavorites(favorites);
    window.dispatchEvent(new CustomEvent('favoritesChanged'));
  }
}

/**
 * Toggle planned pick state for a favorite event.
 */
export function toggleFootprint(eventId: string): void {
  if (!isFavorite(eventId)) return;
  if (isFootprint(eventId)) {
    removeFootprint(eventId);
  } else {
    addFootprint(eventId);
  }
}

/**
 * Get event details by combining event with band and location data
 */
export function getEventWithDetails(event: Event, schedule: Schedule): EventWithDetails | null {
  const band = schedule.bands.find(b => b.id === event.bandId);
  const location = schedule.locations.find(l => l.id === event.locationId);
  
  if (!band || !location) {
    return null;
  }
  
  return {
    ...event,
    band,
    location
  };
}

/**
 * Get all events with details
 */
export function getAllEventsWithDetails(schedule: Schedule): EventWithDetails[] {
  return schedule.events
    .map(event => getEventWithDetails(event, schedule))
    .filter((event): event is EventWithDetails => event !== null);
}

/** Event IDs from storage that still exist in the loaded schedule. */
export function getFavoriteIdsForSchedule(schedule: Schedule | null): string[] {
  const favorites = loadFavorites();
  if (!schedule) {
    return [];
  }
  const validIds = new Set(schedule.events.map((event) => event.id));
  return favorites.events.filter((id) => validIds.has(id));
}

/** Count favorites that exist in the current schedule (excludes stale IDs from prior years). */
export function getFavoriteCountForSchedule(schedule: Schedule | null): number {
  return getFavoriteIdsForSchedule(schedule).length;
}

/** Count planned picks (footprints) that are still valid for the current schedule. */
export function getFootprintCountForSchedule(schedule: Schedule | null): number {
  const favorites = loadFavorites();
  const validFavoriteIds = new Set(getFavoriteIdsForSchedule(schedule));
  return favorites.footprints.filter((id) => validFavoriteIds.has(id)).length;
}

/**
 * Remove favorite and footprint IDs that no longer exist in the schedule.
 * @returns true when storage was updated
 */
export function pruneFavoritesToSchedule(schedule: Schedule): boolean {
  const favorites = loadFavorites();
  const validIds = new Set(schedule.events.map((event) => event.id));
  const prunedEvents = favorites.events.filter((id) => validIds.has(id));
  const prunedFootprints = favorites.footprints.filter((id) => validIds.has(id));

  if (
    prunedEvents.length === favorites.events.length &&
    prunedFootprints.length === favorites.footprints.length
  ) {
    return false;
  }

  saveFavorites({ events: prunedEvents, footprints: prunedFootprints });
  window.dispatchEvent(new CustomEvent('favoritesChanged'));
  return true;
}

/**
 * Get favorite events with details
 */
export function getFavoriteEventsWithDetails(schedule: Schedule): EventWithDetails[] {
  const favoriteIds = new Set(getFavoriteIdsForSchedule(schedule));
  return schedule.events
    .filter((event) => favoriteIds.has(event.id))
    .map((event) => getEventWithDetails(event, schedule))
    .filter((event): event is EventWithDetails => event !== null);
}

/** True when `event` matches a free-text search (band, genre, venue, time, category). */
export function eventMatchesSearchTerm(event: EventWithDetails, searchTerm: string): boolean {
  const raw = searchTerm.trim();
  if (!raw) {
    return true;
  }

  const q = raw.toLowerCase();
  const categoryLabel =
    event.category === 'band' ? 'band' :
    event.category === 'show' ? 'show' :
    event.category === 'other' ? 'other' :
    '';

  const fields = [
    event.band.name,
    event.band.genre,
    event.band.country,
    event.location.name,
    event.location.city,
    event.location.address,
    event.date,
    event.startTime,
    event.endTime,
    categoryLabel
  ].filter((x): x is string => !!x && x.length > 0);

  return fields.some(field => field.toLowerCase().includes(q));
}

/** Strip legacy persisted fields so only facets remain (nav search lives outside localStorage filters). */
export function normalizeFacetFilters(raw: unknown): FacetFilterOptions {
  if (!raw || typeof raw !== 'object') {
    return { ...EMPTY_FACET_FILTERS };
  }
  const o = raw as Record<string, unknown>;
  return {
    date: typeof o.date === 'string' ? o.date : '',
    locationId: typeof o.locationId === 'string' ? o.locationId : '',
    category: typeof o.category === 'string' ? o.category : '',
    myPicksOnly: o.myPicksOnly === true,
  };
}

/** Apply facet filters plus nav search query (header search). */
export function filterEventsWithNavSearch(
  events: EventWithDetails[],
  facets: FacetFilterOptions,
  searchTerm: string,
): EventWithDetails[] {
  return filterEventsByOptions(events, { ...facets, searchTerm });
}

/**
 * Apply facet filters plus optional nav/search text.
 */
export function filterEventsByOptions(events: EventWithDetails[], filters: EventListFilters): EventWithDetails[] {
  return events.filter((event) => {
    if (filters.date && event.date !== filters.date) return false;
    if (filters.locationId && event.locationId !== filters.locationId) return false;
    if (filters.category && event.category !== filters.category) return false;
    if (filters.myPicksOnly && !isFavorite(event.id)) return false;
    return eventMatchesSearchTerm(event, filters.searchTerm);
  });
}

/**
 * Sort events by date and time
 */
export function sortEventsByDateTime(events: EventWithDetails[]): EventWithDetails[] {
  return [...events].sort((a, b) => {
    // First compare by date
    const dateComparison = new Date(a.date).getTime() - new Date(b.date).getTime();
    if (dateComparison !== 0) {
      return dateComparison;
    }
    
    // If same date, compare by start time
    return a.startTime.localeCompare(b.startTime);
  });
}

/**
 * Convert full event IDs to shortened hashes using the minimal collision-free length for this schedule.
 */
export function shortenEventIds(eventIds: string[], schedule: Schedule): string[] {
  const corpusIds = schedule.events.map(e => e.id);
  const len = computeMinimalSpreadHashLength(corpusIds);
  return eventIds.map(id => spreadHashChars(id, len));
}

/**
 * Find full event ID from shortened hash by looking up in the schedule.
 * Prefer exact match at the schedule's minimal length; accept a unique shorter prefix for older share links.
 */
export function findFullEventId(shortHash: string, schedule: Schedule): string | null {
  const len = computeMinimalSpreadHashLength(schedule.events.map(e => e.id));

  const exact = schedule.events.find(event => spreadHashChars(event.id, len) === shortHash);
  if (exact) {
    return exact.id;
  }

  const candidates = schedule.events.filter(event =>
    spreadHashChars(event.id, len).startsWith(shortHash)
  );
  return candidates.length === 1 ? candidates[0].id : null;
}

/**
 * Convert shortened event IDs back to full IDs using the schedule data
 */
export function expandEventIds(shortIds: string[], schedule: Schedule): string[] {
  return shortIds
    .map(shortId => findFullEventId(shortId, schedule))
    .filter((id): id is string => id !== null);
}

/**
 * Generate a shareable link for a list of events using shortened hashes.
 * Pass `baseOrigin` to override `window.location.origin` (e.g. in tests).
 */
export function generateShareableLink(eventIds: string[], baseOrigin?: string): string {
  const baseUrl = baseOrigin ?? window.location.origin;
  const schedule = loadSchedule();
  const shortIds = schedule
    ? shortenEventIds(eventIds, schedule)
    : eventIds.map(id => spreadHashChars(id, 4));
  const encodedData = btoa(JSON.stringify(shortIds));
  return `${baseUrl}/shared?schedule=${encodedData}`;
}

/**
 * Decode a shared schedule from a URL parameter and expand shortened IDs
 */
export function decodeSharedSchedule(encodedData: string): string[] {
  try {
    const decodedData = atob(encodedData);
    const shortIds = JSON.parse(decodedData);
    
    // Load the schedule to expand shortened IDs
    const schedule = loadSchedule();
    if (!schedule) {
      console.error('Schedule not loaded, cannot expand shortened IDs');
      return []; // Return empty array if schedule not available
    }
    
    // Expand shortened IDs to full IDs
    return expandEventIds(shortIds, schedule);
  } catch (error) {
    console.error('Error decoding shared schedule:', error);
    return [];
  }
}

/**
 * Find a band by ID
 */
export function findBandById(bandId: string, schedule: Schedule): Band | undefined {
  return schedule.bands.find(band => band.id === bandId);
}

/**
 * Find events for a specific band
 */
export function findEventsByBandId(bandId: string, schedule: Schedule): EventWithDetails[] {
  return schedule.events
    .filter(event => event.bandId === bandId)
    .map(event => getEventWithDetails(event, schedule))
    .filter((event): event is EventWithDetails => event !== null);
}

/**
 * Converts a country code to its corresponding flag emoji
 * @param countryCode - The country code (e.g., "D", "UK", "US") or multiple codes separated by "/" (e.g., "USA/N")
 * @returns The flag emoji(s) or empty string if no valid country code
 */
export function getCountryFlag(countryCode?: string): string {
  if (!countryCode) return '';
  
  // Handle multiple countries separated by "/"
  if (countryCode.includes('/')) {
    const countries = countryCode.split('/').map(code => code.trim());
    return countries.map(code => getSingleCountryFlag(code)).filter(flag => flag !== '').join('');
  }
  
  return getSingleCountryFlag(countryCode);
}

/**
 * Helper function to convert a single country code to flag emoji
 */
function getSingleCountryFlag(countryCode: string): string {
  if (!countryCode) return '';
  
  // Handle special cases for country codes that don't match ISO standards
  const codeMapping: { [key: string]: string } = {
    'D': 'DE',    // Germany
    'UK': 'GB',   // United Kingdom
    'A': 'AT',    // Austria
    'CH': 'CH',   // Switzerland
    'F': 'FR',    // France
    'I': 'IT',    // Italy
    'E': 'ES',    // Spain
    'P': 'PT',    // Portugal
    'NL': 'NL',   // Netherlands
    'B': 'BE',    // Belgium
    'DK': 'DK',   // Denmark
    'S': 'SE',    // Sweden
    'N': 'NO',    // Norway
    'FIN': 'FI',  // Finland
    'PL': 'PL',   // Poland
    'CZ': 'CZ',   // Czech Republic
    'H': 'HU',    // Hungary
    'RO': 'RO',   // Romania
    'BG': 'BG',   // Bulgaria
    'HR': 'HR',   // Croatia
    'SLO': 'SI',  // Slovenia
    'SK': 'SK',   // Slovakia
    'EST': 'EE',  // Estonia
    'LV': 'LV',   // Latvia
    'LT': 'LT',   // Lithuania
    'RUS': 'RU',  // Russia
    'UA': 'UA',   // Ukraine
    'US': 'US',   // United States
    'USA': 'US',  // United States
    'CDN': 'CA',  // Canada
    'MEX': 'MX',  // Mexico
    'AUS': 'AU',  // Australia
    'NZ': 'NZ',   // New Zealand
    'J': 'JP',    // Japan
    'KR': 'KR',   // South Korea
    'CN': 'CN',   // China
    'IND': 'IN',  // India
    'BR': 'BR',   // Brazil
    'ARG': 'AR',  // Argentina
    'CL': 'CL',   // Chile
    'ZA': 'ZA',   // South Africa
    'EGY': 'EG',  // Egypt
    'IL': 'IL',   // Israel
    'TR': 'TR',   // Turkey
  };
  
  // Get the proper ISO code
  const isoCode = codeMapping[countryCode.toUpperCase()] || countryCode.toUpperCase();
  
  // Convert to flag emoji using regional indicator symbols
  if (isoCode.length === 2) {
    const firstChar = String.fromCodePoint(0x1F1E6 + isoCode.charCodeAt(0) - 65);
    const secondChar = String.fromCodePoint(0x1F1E6 + isoCode.charCodeAt(1) - 65);
    return firstChar + secondChar;
  }
  
  return '';
}

export function filterEvents(
  events: EventWithDetails[],
  filters: FilterOptions,
): EventWithDetails[] {
  let filtered = [...events];

  if (filters.date) {
    filtered = filtered.filter((event) => event.date === filters.date);
  }

  if (filters.locationId) {
    filtered = filtered.filter((event) => event.locationId === filters.locationId);
  }

  if (filters.category) {
    filtered = filtered.filter((event) => event.category === filters.category);
  }

  if (filters.searchTerm) {
    const searchLower = filters.searchTerm.toLowerCase();
    filtered = filtered.filter(
      (event) =>
        event.band.name.toLowerCase().includes(searchLower) ||
        (event.band.genre && event.band.genre.toLowerCase().includes(searchLower)),
    );
  }

  return filtered;
}

/**
 * Load facet filter settings from localStorage (does not include nav search query).
 */
export function loadFilters(): FacetFilterOptions | null {
  const filtersData = localStorage.getItem(SCHEDULE_FILTER_STORAGE_KEY);
  if (filtersData) {
    try {
      return normalizeFacetFilters(JSON.parse(filtersData));
    } catch (error) {
      console.error('Error parsing filter data:', error);
      return null;
    }
  }
  return null;
}

/**
 * Save facet filter settings to localStorage
 */
export function saveFilters(filters: FacetFilterOptions): void {
  try {
    localStorage.setItem(SCHEDULE_FILTER_STORAGE_KEY, JSON.stringify(filters));
  } catch (error) {
    console.warn('Failed to save filters to localStorage:', error);
  }
}

/**
 * Clear saved filter settings
 */
export function clearFilters(): void {
  try {
    localStorage.removeItem(SCHEDULE_FILTER_STORAGE_KEY);
  } catch (error) {
    console.warn('Failed to clear filters from localStorage:', error);
  }
}