import { hasWebKitScrollRestoreQuirk } from './platform';

/** Viewport-sized scroll pane used for page content and view-transition capture. */
export const PAGE_SCROLL_ID = 'page-scroll';

const scrollPositions = new Map<string, number>();
/** Layout settle budget before smooth scroll starts to a capped target (~400ms at 60Hz). */
const RESTORE_MAX_FRAMES = 24;
const RESTORE_SMOOTH_VERIFY_FRAMES = 60;
const RESTORE_SMOOTH_SETTLE_FRAMES = 4;
const RESTORE_SMOOTH_GRACE_MS = 450;
const RESTORE_LAYOUT_TIMEOUT_MS = 3000;
let restoreLoopId = 0;
let layoutWatchId = 0;

function nextFrame(): Promise<void> {
  return new Promise((resolve) => requestAnimationFrame(() => resolve()));
}

function forceScrollLayout(el: HTMLElement): void {
  void el.getBoundingClientRect();
}

function afterTransitionFrames(run: () => void): void {
  void (async () => {
    await nextFrame();
    await nextFrame();
    run();
  })();
}

export function getPageScrollElement(): HTMLElement | null {
  return document.getElementById(PAGE_SCROLL_ID);
}

function getPageScrollTop(): number {
  return getPageScrollElement()?.scrollTop ?? 0;
}

export function scrollPageTo(top: number, behavior: ScrollBehavior = 'auto'): void {
  const el = getPageScrollElement();
  if (!el) return;
  if (el.scrollTop === top && el.scrollLeft === 0) return;
  if (typeof el.scrollTo === 'function') {
    el.scrollTo({ top, left: 0, behavior });
  } else {
    el.scrollTop = top;
    el.scrollLeft = 0;
  }
}

export function scrollPageToTop(): void {
  scrollPageTo(0);
}

/** Apply stamped scroll after navigation; `null` means scroll to top. */
export function applyPageScrollRestore(
  restoreTop: number | null,
  deferred: boolean,
  smooth = false,
): void {
  if (restoreTop !== null) {
    if (deferred) restorePageScrollAfterTransition(restoreTop, smooth);
    else restorePageScroll(restoreTop, smooth);
    return;
  }
  if (deferred) scrollPageToTopAfterTransition();
  else scrollPageToTop();
}

/** Detail routes always open at the top — no scroll restore. */
export function isDetailPath(path: string): boolean {
  return path.startsWith('/band/');
}

export function savePageScrollForPath(path: string): void {
  if (isDetailPath(path)) return;
  scrollPositions.set(path, getPageScrollTop());
}

export function peekSavedPageScroll(path: string): number | undefined {
  return scrollPositions.get(path);
}

/** Saved scroll to restore when revisiting a path, or `null` for a fresh top. */
export function restoreScrollTopForPath(path: string | undefined): number | null {
  if (!path || isDetailPath(path)) return null;
  const saved = peekSavedPageScroll(path);
  return saved !== undefined ? saved : null;
}

/** Apply a saved scroll position, retrying while layout is still settling. */
export function restorePageScroll(top: number, smooth = false): void {
  runScrollRestoreLoop(top, { smooth, useDirectApply: false });
}

/** WebKit: defer scroll until after VT teardown (snapshot/compositor race). */
export function restorePageScrollAfterTransition(top: number, smooth = false): void {
  afterTransitionFrames(() =>
    runScrollRestoreLoop(top, {
      smooth,
      useDirectApply: !smooth || hasWebKitScrollRestoreQuirk(),
    }),
  );
}

export function scrollPageToTopAfterTransition(): void {
  afterTransitionFrames(() => {
    scrollPageToTop();
    const el = getPageScrollElement();
    if (el) forceScrollLayout(el);
  });
}

function applyScrollPositionDirect(top: number): void {
  const el = getPageScrollElement();
  if (!el) return;
  if (el.scrollTop === top && el.scrollLeft === 0) return;
  el.scrollTop = top;
  el.scrollLeft = 0;
  forceScrollLayout(el);
}

function setScrollRestoreLayoutHint(active: boolean): void {
  getPageScrollElement()?.classList.toggle('scroll-restore-active', active);
}

function finishScrollRestoreLoop(loopId: number): void {
  if (loopId === restoreLoopId) {
    setScrollRestoreLayoutHint(false);
  }
}

function isScrollRestoreComplete(el: HTMLElement, top: number): boolean {
  const maxTop = Math.max(0, el.scrollHeight - el.clientHeight);
  const target = Math.min(top, maxTop);
  const canReachFullTarget = maxTop + 1 >= top;
  return Math.abs(el.scrollTop - target) <= 1 && canReachFullTarget;
}

function watchScrollLayoutUntilRestored(
  loopId: number,
  el: HTMLElement,
  top: number,
  applyInstant: (target: number) => void,
): void {
  const watchId = ++layoutWatchId;
  const started = performance.now();
  let observer: ResizeObserver | undefined;

  const stop = () => {
    observer?.disconnect();
    finishScrollRestoreLoop(loopId);
  };

  const attempt = () => {
    if (loopId !== restoreLoopId || watchId !== layoutWatchId) {
      stop();
      return;
    }

    const maxTop = Math.max(0, el.scrollHeight - el.clientHeight);
    applyInstant(Math.min(top, maxTop));

    if (isScrollRestoreComplete(el, top)) {
      stop();
      return;
    }

    if (performance.now() - started > RESTORE_LAYOUT_TIMEOUT_MS) {
      stop();
      return;
    }

    requestAnimationFrame(attempt);
  };

  if (typeof ResizeObserver !== 'undefined') {
    observer = new ResizeObserver(() => attempt());
    observer.observe(el);
    for (const child of el.children) {
      observer.observe(child);
    }
  }

  attempt();
}

function verifySmoothScrollRestore(
  loopId: number,
  el: HTMLElement,
  top: number,
  applyInstant: (target: number) => void,
): void {
  let settled = false;
  const startedAt = performance.now();
  const startScrollTop = el.scrollTop;

  const finish = () => {
    if (settled || loopId !== restoreLoopId) return;
    settled = true;

    if (isScrollRestoreComplete(el, top)) {
      finishScrollRestoreLoop(loopId);
      return;
    }

    const maxTop = Math.max(0, el.scrollHeight - el.clientHeight);
    applyInstant(Math.min(top, maxTop));
    if (!isScrollRestoreComplete(el, top)) {
      watchScrollLayoutUntilRestored(loopId, el, top, applyInstant);
    } else {
      finishScrollRestoreLoop(loopId);
    }
  };

  if ('onscrollend' in el) {
    el.addEventListener('scrollend', finish, { once: true });
  }

  let frames = 0;
  let lastScrollTop = el.scrollTop;
  let stableFrames = 0;

  const verify = () => {
    if (settled || loopId !== restoreLoopId) return;

    if (isScrollRestoreComplete(el, top)) {
      finishScrollRestoreLoop(loopId);
      settled = true;
      return;
    }

    const hasMoved = el.scrollTop !== startScrollTop;
    const graceActive = performance.now() - startedAt < RESTORE_SMOOTH_GRACE_MS;
    if (graceActive && !hasMoved) {
      frames += 1;
      requestAnimationFrame(verify);
      return;
    }

    if (el.scrollTop === lastScrollTop) {
      stableFrames += 1;
    } else {
      stableFrames = 0;
      lastScrollTop = el.scrollTop;
    }

    if (stableFrames >= RESTORE_SMOOTH_SETTLE_FRAMES || frames >= RESTORE_SMOOTH_VERIFY_FRAMES) {
      finish();
      return;
    }

    frames += 1;
    requestAnimationFrame(verify);
  };

  requestAnimationFrame(verify);
}

function runScrollRestoreLoop(
  top: number,
  options: { smooth?: boolean; useDirectApply?: boolean } = {},
): void {
  const loopId = ++restoreLoopId;
  layoutWatchId += 1;
  const { smooth = false, useDirectApply = false } = options;
  const el = getPageScrollElement();
  if (!el) return;

  setScrollRestoreLayoutHint(true);
  forceScrollLayout(el);

  const applyInstant = useDirectApply
    ? applyScrollPositionDirect
    : (target: number) => scrollPageTo(target, 'auto');

  let frames = 0;
  const tick = () => {
    if (loopId !== restoreLoopId) return;

    forceScrollLayout(el);
    const maxTop = Math.max(0, el.scrollHeight - el.clientHeight);
    const target = Math.min(top, maxTop);
    const canReachFullTarget = maxTop + 1 >= top;

    if (smooth) {
      if (canReachFullTarget || frames >= RESTORE_MAX_FRAMES) {
        scrollPageTo(target, 'smooth');
        verifySmoothScrollRestore(loopId, el, top, applyInstant);
        return;
      }
    } else {
      applyInstant(target);

      const atTarget = Math.abs(el.scrollTop - target) <= 1;
      if (atTarget && canReachFullTarget) {
        finishScrollRestoreLoop(loopId);
        return;
      }

      if (frames >= RESTORE_MAX_FRAMES) {
        if (!isScrollRestoreComplete(el, top)) {
          watchScrollLayoutUntilRestored(loopId, el, top, applyInstant);
        } else {
          finishScrollRestoreLoop(loopId);
        }
        return;
      }
    }

    frames += 1;
    requestAnimationFrame(tick);
  };

  tick();
}
