import React, { useEffect, useState } from 'react';

interface FavoriteStarButtonProps {
  filled: boolean;
  onClick: (e: React.MouseEvent) => void;
  size?: 'sm' | 'md';
  className?: string;
  animateOnToggle?: boolean;
}

export function FavoriteStarButton({
  filled,
  onClick,
  size = 'md',
  className = '',
  animateOnToggle = false,
}: FavoriteStarButtonProps) {
  const [pop, setPop] = useState(false);

  useEffect(() => {
    if (!pop) return;
    const timer = window.setTimeout(() => setPop(false), 320);
    return () => window.clearTimeout(timer);
  }, [pop]);

  const handleClick = (e: React.MouseEvent) => {
    onClick(e);
    if (animateOnToggle) setPop(true);
  };

  const iconClass = size === 'sm' ? 'w-5 h-5' : 'w-6 h-6 md:w-7 md:h-7';
  const hitArea = size === 'sm' ? 'p-1.5 -m-1.5' : 'p-2 -m-2 min-w-11 min-h-11';

  return (
    <button
      type="button"
      onClick={handleClick}
      className={`favorite-icon shrink-0 inline-flex items-center justify-center ${hitArea} ${filled ? 'active' : ''} ${pop ? 'favorite-icon--pop' : ''} ${className}`.trim()}
      aria-label={filled ? 'Remove from my schedule' : 'Add to my schedule'}
      aria-pressed={filled}
    >
      <svg
        className={iconClass}
        viewBox="0 0 24 24"
        fill={filled ? 'currentColor' : 'none'}
        stroke="currentColor"
        strokeWidth={filled ? 0 : 1.5}
        aria-hidden="true"
      >
        <path
          strokeLinecap="round"
          strokeLinejoin="round"
          d="M11.48 3.499a.562.562 0 011.04 0l2.125 5.111a.563.563 0 00.475.345l5.518.442c.499.04.701.663.321.988l-4.204 3.602a.563.563 0 00-.182.557l1.285 5.385a.562.562 0 01-.84.61l-4.725-2.885a.563.563 0 00-.586 0L6.982 20.54a.562.562 0 01-.84-.61l1.285-5.386a.562.562 0 00-.182-.557l-4.204-3.602a.563.563 0 01.321-.988l5.518-.442a.563.563 0 00.475-.345L11.48 3.5z"
        />
      </svg>
    </button>
  );
}
