import React, { useState, useEffect, useMemo } from 'react';
import type { Schedule, EventWithDetails, FacetFilterOptions } from '../models/types';
import { EMPTY_FACET_FILTERS } from '../models/types';
import {
  buildFavoritesSnapshot,
  getCachedFavoritesSnapshot,
  loadScheduleData,
  isScheduleLoaded,
} from '../utils/apiUtils';
import {
  generateShareableLink,
  decodeSharedSchedule,
  addFavorite,
  saveFavorites,
  loadFavorites,
  getAllEventsWithDetails,
  filterEventsWithNavSearch,
} from '../utils/dataUtils';
import { groupEventsByDate } from '../utils/scheduleUtils';
import { FavoritesDaySection } from '../components/FavoritesDaySection';
import { EventFilter } from '../components/EventFilter';
import { SkeletonLoader } from '../components/SkeletonLoader';
import { loadDayGroupStates, toggleDayExpanded, isDayExpanded } from '../utils/dayGroupUtils';
import { useNavigationSearch } from '../context/NavigationSearch';
import { useScrollToTopOnNavSearchChange } from '../hooks/useScrollToTopOnNavSearchChange';

const cachedFavorites = getCachedFavoritesSnapshot();

export function Favorites() {
  const [schedule, setSchedule] = useState<Schedule | null>(cachedFavorites?.schedule ?? null);
  const [favoriteEvents, setFavoriteEvents] = useState<EventWithDetails[]>(
    cachedFavorites?.favoriteEvents ?? [],
  );
  const [loading, setLoading] = useState(!isScheduleLoaded());
  const [error, setError] = useState<string | null>(null);
  const [uniqueDates, setUniqueDates] = useState<string[]>(cachedFavorites?.uniqueDates ?? []);
  const [shareUrl, setShareUrl] = useState<string>('');
  const [showShareLink, setShowShareLink] = useState(false);
  const [copied, setCopied] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [expandedDays, setExpandedDays] = useState<Record<string, boolean>>({});

  // Import functionality state
  const [showImportSection, setShowImportSection] = useState(false);
  const [importText, setImportText] = useState('');
  const [importError, setImportError] = useState<string | null>(null);
  const [importSuccess, setImportSuccess] = useState<string | null>(null);
  const [mergeMode, setMergeMode] = useState(true); // true = merge, false = replace

  const [facetFilters, setFacetFilters] = useState<FacetFilterOptions>(EMPTY_FACET_FILTERS);

  const { query: navSearchQuery } = useNavigationSearch();

  const filteredEvents = useMemo(
    () => filterEventsWithNavSearch(favoriteEvents, facetFilters, navSearchQuery),
    [favoriteEvents, facetFilters, navSearchQuery],
  );

  useScrollToTopOnNavSearchChange();

  // Set up scroll position tracking and load day group states
  useEffect(() => {
    const dayGroupStates = loadDayGroupStates();
    setExpandedDays(dayGroupStates);
  }, []);

  // Set up scroll position tracking
  // Load schedule data only once on component mount
  useEffect(() => {
    async function fetchData() {
      try {
        const data = await loadScheduleData();
        const snapshot = buildFavoritesSnapshot(data);
        setSchedule(snapshot.schedule);
        setFavoriteEvents(snapshot.favoriteEvents);
        setUniqueDates(snapshot.uniqueDates);
      } catch (err) {
        setError('Failed to load your schedule. Please try again later.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, []); // Empty dependency array means this runs once on mount

  // Separate effect to handle favorites changes
  useEffect(() => {
    if (!schedule) return; // Skip if schedule isn't loaded yet

    const processData = (data: Schedule) => {
      const snapshot = buildFavoritesSnapshot(data);
      setFavoriteEvents(snapshot.favoriteEvents);
      setUniqueDates(snapshot.uniqueDates);
    };

    // Add event listener to update favorites when they change
    const handleFavoritesChange = () => {
      processData(schedule);
    };

    // Keep storage event for cross-tab synchronization, but only for favorites changes
    const handleStorageChange = (event: StorageEvent) => {
      if (event.key === 'wgt-favorites') {
        processData(schedule);
      }
    };

    window.addEventListener('favoritesChanged', handleFavoritesChange);
    window.addEventListener('storage', handleStorageChange);

    return () => {
      window.removeEventListener('favoritesChanged', handleFavoritesChange);
      window.removeEventListener('storage', handleStorageChange);
    };
  }, [schedule]); // Only re-run when schedule changes

  const handleFacetChange = (filters: FacetFilterOptions) => {
    setFacetFilters(filters);
  };

  const handleShareSchedule = () => {
    const eventIds = favoriteEvents.map(event => event.id);
    const url = generateShareableLink(eventIds);
    setShareUrl(url);
    setShowShareLink(true);
    setCopied(false);
  };

  const handleCopyLink = () => {
    navigator.clipboard.writeText(shareUrl).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleResetData = () => {
    setShowResetConfirm(true);
  };

  const confirmResetData = () => {
    localStorage.clear();
    window.location.reload();
  };

  const cancelResetData = () => {
    setShowResetConfirm(false);
  };

  // Import functionality handlers
  const handleImportSchedule = () => {
    setImportError(null);
    setImportSuccess(null);

    if (!importText.trim()) {
      setImportError('Please enter a shared schedule URL or data');
      return;
    }

    try {
      let eventIds: string[] = [];

      // Check if it's a URL
      if (importText.includes('/shared?schedule=') || importText.includes('schedule=')) {
        // Extract the schedule parameter from URL
        const url = new URL(importText.includes('http') ? importText : `${window.location.origin}${importText}`);
        const scheduleParam = url.searchParams.get('schedule');
        if (!scheduleParam) {
          throw new Error('Invalid shared schedule URL');
        }
        eventIds = decodeSharedSchedule(scheduleParam);
      } else {
        // Try to parse as direct encoded data
        eventIds = decodeSharedSchedule(importText);

        if (eventIds.length === 0) {
          // Try to parse as JSON array of event IDs
          const parsed = JSON.parse(importText);
          if (Array.isArray(parsed)) {
            eventIds = parsed;
          } else if (parsed.events && Array.isArray(parsed.events)) {
            // Handle favorites format
            eventIds = parsed.events;
          } else {
            throw new Error('Invalid data format. Expected an array of event IDs or an object with an "events" property containing an array.');
          }
        }
      }

      if (eventIds.length === 0) {
        throw new Error('No valid events found in the data');
      }

      console.log('Imported event IDs:', eventIds);

      // Validate that the events exist in the current schedule
      if (schedule) {
        const allEvents = getAllEventsWithDetails(schedule);
        const allEventIds = allEvents.map(event => event.id);

        console.log('Total events in schedule:', allEvents.length);
        console.log('Sample event IDs from schedule:', allEventIds.slice(0, 5));
        console.log('Imported event IDs:', eventIds.slice(0, 5));

        const validEventIds = eventIds.filter(id =>
          allEventIds.includes(id)
        );

        console.log('Valid event IDs found:', validEventIds.length);

        if (validEventIds.length === 0) {
          // Provide more detailed error information
          const sampleImported = eventIds.slice(0, 3);
          const sampleSchedule = allEventIds.slice(0, 3);
          throw new Error(
            `None of the events in the shared data exist in the current schedule.\n\n` +
            `Sample imported IDs: ${sampleImported.join(', ')}\n` +
            `Sample schedule IDs: ${sampleSchedule.join(', ')}\n\n` +
            `This usually means the data is from a different version of the schedule or contains invalid event IDs.`
          );
        }

        // Import the events
        if (mergeMode) {
          // Merge with existing favorites
          validEventIds.forEach(eventId => {
            addFavorite(eventId);
          });
          setImportSuccess(`Imported ${validEventIds.length} events and merged with your schedule`);
        } else {
          // Replace existing favorites
          const currentFavorites = loadFavorites();
          currentFavorites.events = validEventIds;
          saveFavorites(currentFavorites);
          setImportSuccess(`Replaced your schedule with ${validEventIds.length} events`);
        }

        if (validEventIds.length < eventIds.length) {
          setImportError(`Note: ${eventIds.length - validEventIds.length} events were not found in the current schedule and were skipped.`);
        }

        // Refresh the favorites display
        setFavoriteEvents(buildFavoritesSnapshot(schedule).favoriteEvents);

        // Clear the import text
        setImportText('');
      } else {
        throw new Error('Schedule data not loaded');
      }
    } catch (error) {
      console.error('Import error:', error);
      setImportError(error instanceof Error ? error.message : 'Failed to import schedule data');
    }
  };

  const handleFileImport = (event: Event) => {
    const input = event.target as HTMLInputElement;
    const file = input.files?.[0];

    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      const content = e.target?.result as string;
      setImportText(content);
      setImportError(null);
      setImportSuccess(null);
    };
    reader.onerror = () => {
      setImportError('Failed to read file');
    };
    reader.readAsText(file);
  };

  const handleExportFavorites = () => {
    const favorites = loadFavorites();
    const dataStr = JSON.stringify(favorites, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });

    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'wgt-favorites-backup.json';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const toggleImportSection = () => {
    setShowImportSection(!showImportSection);
    setImportError(null);
    setImportSuccess(null);
    setImportText('');
  };

  const handleToggleDayExpanded = (date: string) => {
    const newExpandedDays = toggleDayExpanded(date, expandedDays);
    setExpandedDays(newExpandedDays);
  };

  const isExpanded = (date: string) => {
    return isDayExpanded(date, expandedDays);
  };

  if (loading) {
    return <SkeletonLoader message="Loading your schedule..." showDays={false} itemCount={3} />;
  }

  if (error) {
    return (
      <div className="bg-red-900 text-white p-4 rounded-lg">
        <h2 className="text-xl font-bold mb-2">Error</h2>
        <p>{error}</p>
      </div>
    );
  }

  return (
    <div>
      <div className="flex flex-col md:flex-row md:justify-between md:items-center mb-6">
        <h1 className="font-display text-3xl md:text-4xl text-wgt-fog mb-4 md:mb-0">My Festival Schedule</h1>

        <div className="flex flex-col sm:flex-row gap-2">
          <button
            onClick={toggleImportSection}
            className="btn btn-secondary"
          >
            {showImportSection ? 'Hide Import' : 'Import Schedule'}
          </button>

          {favoriteEvents.length > 0 && (
            <>
              <button
                onClick={handleExportFavorites}
                className="btn btn-secondary"
              >
                Export Backup
              </button>
              <button
                onClick={handleShareSchedule}
                className="btn btn-primary"
              >
                Share My Schedule
              </button>
            </>
          )}
        </div>
      </div>

      {/* Import Section */}
      {showImportSection && (
        <div className="bg-gray-800 p-4 rounded-lg mb-6">
          <h3 className="text-lg font-semibold mb-4">Import Schedule Data</h3>

          <div className="space-y-4">
            {/* Import mode toggle */}
            <div className="flex items-center space-x-4">
              <label className="text-sm font-medium">Import Mode:</label>
              <label className="flex items-center">
                <input
                  type="radio"
                  name="importMode"
                  checked={mergeMode}
                  onChange={() => setMergeMode(true)}
                  className="mr-2"
                />
                Merge with my schedule
              </label>
              <label className="flex items-center">
                <input
                  type="radio"
                  name="importMode"
                  checked={!mergeMode}
                  onChange={() => setMergeMode(false)}
                  className="mr-2"
                />
                Replace my schedule
              </label>
            </div>

            {/* Text input for URLs or data */}
            <div>
              <label className="block text-sm font-medium mb-2">
                Paste shared schedule URL or encoded data:
              </label>
              <textarea
                value={importText}
                onChange={(e) => setImportText((e.target as HTMLTextAreaElement).value)}
                placeholder="Paste a shared schedule URL (like: https://yoursite.com/shared?schedule=...) or encoded data here"
                className="w-full bg-gray-700 text-white rounded p-3 border border-gray-600 min-h-[100px] resize-y"
              />
            </div>

            {/* File input */}
            <div>
              <label className="block text-sm font-medium mb-2">
                Or select a backup file:
              </label>
              <input
                type="file"
                accept=".json,.txt"
                onChange={handleFileImport}
                className="block w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded file:border-0 file:text-sm file:font-semibold file:bg-blue-600 file:text-white hover:file:bg-blue-700"
              />
            </div>

            {/* Action buttons */}
            <div className="flex gap-2">
              <button
                onClick={handleImportSchedule}
                disabled={!importText.trim()}
                className="btn btn-primary disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Import Schedule
              </button>
              <button
                onClick={() => setImportText('')}
                className="btn btn-secondary"
              >
                Clear
              </button>
            </div>

            {/* Error/Success messages */}
            {importError && (
              <div className="bg-red-900 text-red-200 p-3 rounded">
                <pre className="whitespace-pre-wrap text-sm">{importError}</pre>
              </div>
            )}
            {importSuccess && (
              <div className="bg-green-900 text-green-200 p-3 rounded">
                {importSuccess}
              </div>
            )}
          </div>
        </div>
      )}

      {showShareLink && (
        <div className="bg-gray-800 p-4 rounded-lg mb-6">
          <h3 className="text-lg font-semibold mb-2">Share your schedule with friends</h3>
          <div className="flex flex-col sm:flex-row gap-2">
            <input
              type="text"
              value={shareUrl}
              readonly
              className="flex-grow bg-gray-700 text-white rounded p-2 border border-gray-600"
            />
            <button
              onClick={handleCopyLink}
              className="btn btn-secondary"
            >
              {copied ? 'Copied!' : 'Copy Link'}
            </button>
          </div>
        </div>
      )}

      {schedule && favoriteEvents.length > 0 && (
        <div className="sticky top-0 z-40 border-b border-white/5 bg-wgt-void/90 backdrop-blur-md pb-2 -mx-4 px-4 sm:-mx-6 sm:px-6 md:-mx-8 md:px-8">
          <EventFilter
            onFilterChange={handleFacetChange}
            locations={schedule.locations}
            dates={uniqueDates}
            initialFilters={facetFilters}
          />
        </div>
      )}

      {filteredEvents.length > 0 ? (
        <div className="schedule-day-groups">
          {Object.entries(groupEventsByDate(filteredEvents))
            .sort(([a], [b]) => a.localeCompare(b))
            .map(([date, dayEvents]) => (
              <FavoritesDaySection
                key={date}
                date={date}
                events={dayEvents}
                isExpanded={isExpanded(date)}
                onToggleExpanded={handleToggleDayExpanded}
                sourceInfo={{ name: encodeURIComponent('My schedule') }}
                showDaySummary
                showConflicts
                showTravelHints
              />
            ))}
        </div>
      ) : (
        <div className="card text-center py-8">
          <p className="text-xl text-gray-400">
            {favoriteEvents.length > 0
              ? 'No picks match your filter criteria.'
              : 'Build your schedule from the program.'}
          </p>
          <p className="text-gray-500 mt-2">
            {favoriteEvents.length > 0
              ? 'Try adjusting your filter criteria.'
              : 'Open the full schedule and tap the star on any gig you want to catch.'}
          </p>
        </div>
      )}

      {/* Reset Data Section */}
      <div className="mt-12 pt-8 border-t border-gray-700">
        <div className="text-center">
          <h3 className="text-lg font-semibold mb-4 text-gray-300">Danger Zone</h3>
          <button
            onClick={handleResetData}
            className="bg-red-600 hover:bg-red-700 text-white font-bold py-3 px-6 rounded-lg transition-colors duration-200"
          >
            Reset All Data
          </button>
          <p className="text-sm text-gray-400 mt-2">
            This will clear your schedule and cached data
          </p>
        </div>
      </div>

      {/* Reset Confirmation Dialog */}
      {showResetConfirm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-gray-800 p-6 rounded-lg max-w-md mx-4">
            <h3 className="text-xl font-bold mb-4 text-red-400">Confirm Reset</h3>
            <p className="text-gray-300 mb-6">
              Are you sure you want to reset all data? This will:
            </p>
            <ul className="list-disc list-inside text-gray-400 mb-6 space-y-1">
              <li>Clear all bands on your schedule</li>
              <li>Remove cached schedule data</li>
              <li>Reset the app to its initial state</li>
            </ul>
            <p className="text-red-300 font-semibold mb-6">
              This action cannot be undone!
            </p>
            <div className="flex space-x-4">
              <button
                onClick={cancelResetData}
                className="flex-1 bg-gray-600 hover:bg-gray-700 text-white py-2 px-4 rounded transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={confirmResetData}
                className="flex-1 bg-red-600 hover:bg-red-700 text-white py-2 px-4 rounded transition-colors"
              >
                Reset Data
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
